    name: '',
    mobile: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' }
  });

  useEffect(() => {
    const fetchHint = async () => {
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  const handleAuth = () => {
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.BUSINESS_TYPE);
    }, 1500);
  };

  const handleLocationDetect = () => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        setProfile({
          ...profile,
          location: {
            lat: position.coords.latitude,
            lng: position.coords.longitude,
            address: "Lucknow Main Market Area" // Mock geocoding
          }
        });
      });
