  const nextStep = () => {
    if (step === RegistrationStep.BUSINESS_TYPE) setStep(RegistrationStep.LOCATION);
    else if (step === RegistrationStep.LOCATION) setStep(RegistrationStep.DOCUMENTS);
    else if (step === RegistrationStep.DOCUMENTS) setStep(RegistrationStep.REVIEW);
    else if (step === RegistrationStep.REVIEW) onComplete(profile as VendorProfile);
  };

  const prevStep = () => {
    if (step === RegistrationStep.BUSINESS_TYPE) setStep(RegistrationStep.AUTH);
    else if (step === RegistrationStep.LOCATION) setStep(RegistrationStep.BUSINESS_TYPE);
    else if (step === RegistrationStep.DOCUMENTS) setStep(RegistrationStep.LOCATION);
    else if (step === RegistrationStep.REVIEW) setStep(RegistrationStep.DOCUMENTS);
