            {i < 4 && <div className={`h-1 flex-1 mx-2 rounded-full transition-colors duration-500 ${
              i < Object.values(RegistrationStep).indexOf(step) ? 'bg-green-500' : 'bg-gray-100'
            }`}></div>}
          </div>
        ))}
      </div>

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
