      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500 animate-in slide-in-from-top-4">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {/* Progress Line */}
      <div className="flex items-center justify-between mb-12 px-2">
        {Object.values(RegistrationStep).slice(0, 5).map((s, i) => (
          <div key={s} className="flex items-center flex-1 last:flex-none">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all duration-500 ${
              step === s ? 'bg-orange-600 text-white shadow-lg shadow-orange-600/30 scale-110' : 
              i < Object.values(RegistrationStep).indexOf(step) ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-400'
            }`}>
              {i < Object.values(RegistrationStep).indexOf(step) ? <CheckCircle2 className="w-5 h-5" /> : i + 1}
            </div>
            {i < 4 && <div className={`h-1 flex-1 mx-2 rounded-full transition-colors duration-500 ${
              i < Object.values(RegistrationStep).indexOf(step) ? 'bg-green-500' : 'bg-gray-100'
            }`}></div>}
          </div>
        ))}
      </div>

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700 ml-1">मोबाइल नंबर</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000-00000"
                    className="w-full pl-14 pr-4 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 transition-all text-xl tracking-widest font-bold"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value)}
                  />
                </div>
              </div>
              <button 
                onClick={handleAuth}
                disabled={mobile.length !== 10 || isVerifying}
                className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2 disabled:opacity-50 hover:bg-orange-700 transition-all active:scale-[0.98]"
              >
                {isVerifying ? <Loader2 className="w-6 h-6 animate-spin" /> : <><span>OTP भेजें</span> <ArrowRight className="w-5 h-5" /></>}
              </button>
            </div>
            <p className="text-xs text-center text-gray-400">यह मोबाइल नंबर आपके व्यापार कार्ड से लिंक किया जाएगा।</p>
          </div>
        )}

        {step === RegistrationStep.BUSINESS_TYPE && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">व्यापार का प्रकार</h2>
              <p className="text-gray-500">आप किस प्रकार का व्यापार करते हैं? एक विकल्प चुनें।</p>
            </div>
            <div className="grid grid-cols-1 gap-4">
              {BUSINESS_TYPES.map((type) => (
                <button
                  key={type.id}
                  onClick={() => {
                    setProfile({ ...profile, businessType: type.label });
                    nextStep();
                  }}
                  className={`flex items-center p-6 rounded-[28px] border-2 transition-all hover:border-orange-600 group text-left ${
                    profile.businessType === type.label ? 'border-orange-600 bg-orange-50' : 'border-gray-50 bg-gray-50'
                  }`}
                >
                  <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mr-6 transition-all shadow-sm ${
                    profile.businessType === type.label ? 'bg-orange-600 text-white' : 'bg-white text-gray-400 group-hover:text-orange-600'
                  }`}>
                    {type.icon}
                  </div>
                  <div>
                    <p className={`text-lg font-bold ${profile.businessType === type.label ? 'text-orange-900' : 'text-gray-900'}`}>
                      {type.label.split('(')[0].trim()}
