            </div>
            <div className="space-y-6">
              <button 
                onClick={handleLocationDetect}
                className="w-full p-8 border-2 border-dashed border-orange-200 rounded-[32px] bg-orange-50/30 hover:bg-orange-50 transition-colors group flex flex-col items-center justify-center space-y-4"
