                <div className="w-16 h-16 bg-white rounded-2xl shadow-sm flex items-center justify-center group-hover:scale-110 transition-transform">
                  <MapPin className="w-8 h-8 text-orange-600" />
                </div>
                <div className="text-center">
                  <p className="text-lg font-bold text-gray-900">वर्तमान स्थान का उपयोग करें</p>
                  <p className="text-sm text-gray-500">स्वचालित रूप से स्थान का पता लगाएं</p>
                </div>
              </button>

              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700 ml-1">पता (Address)</label>
                <textarea 
                  className="w-full p-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 transition-all text-lg font-medium resize-none h-32"
                  placeholder="दुकान नंबर, गली का नाम, शहर, जिला..."
                  value={profile.location?.address}
                  onChange={(e) => setProfile({ ...profile, location: { ...profile.location!, address: e.target.value } })}
                />
              </div>
            </div>
            <div className="pt-4">
              <button 
                onClick={nextStep}
                disabled={!profile.location?.address}
                className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2 disabled:opacity-50"
              >
                <span>अगला (Next)</span>
                <ArrowRight className="w-5 h-5" />
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.DOCUMENTS && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">दस्तावेज़ (वैकल्पिक)</h2>
              <p className="text-gray-500">यदि आपके पास आधार या पैन है, तो आप स्कैन कर सकते हैं। यह प्रक्रिया नि:शुल्क है।</p>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <button className="aspect-square border-2 border-dashed border-gray-200 rounded-[32px] bg-gray-50 hover:bg-gray-100 transition-colors flex flex-col items-center justify-center space-y-4 group">
                <div className="w-12 h-12 bg-white rounded-2xl shadow-sm flex items-center justify-center group-hover:scale-110 transition-transform">
                  <Camera className="w-6 h-6 text-gray-400" />
                </div>
                <p className="text-xs font-bold text-gray-600 uppercase tracking-widest">Aadhaar Scan</p>
              </button>
              <button className="aspect-square border-2 border-dashed border-gray-200 rounded-[32px] bg-gray-50 hover:bg-gray-100 transition-colors flex flex-col items-center justify-center space-y-4 group">
                <div className="w-12 h-12 bg-white rounded-2xl shadow-sm flex items-center justify-center group-hover:scale-110 transition-transform">
                  <Camera className="w-6 h-6 text-gray-400" />
                </div>
                <p className="text-xs font-bold text-gray-600 uppercase tracking-widest">Shop Photo</p>
              </button>
            </div>
            <div className="p-6 bg-blue-50 rounded-2xl border border-blue-100 flex items-start space-x-3">
              <div className="w-5 h-5 bg-blue-500 rounded-full flex items-center justify-center text-white text-[10px] font-bold mt-0.5">!</div>
              <p className="text-xs text-blue-800 font-medium leading-relaxed">
                दस्तावेज़ अपलोड करना अनिवार्य नहीं है। आप बिना किसी दस्तावेज़ के भी पंजीकरण पूरा कर सकते हैं।
              </p>
            </div>
            <div className="pt-4 flex flex-col space-y-4">
              <button 
                onClick={nextStep}
                className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2"
              >
                <span>सबमिट करें (Submit)</span>
                <CheckCircle2 className="w-5 h-5" />
              </button>
              <button onClick={nextStep} className="text-sm font-bold text-gray-400 hover:text-gray-600 transition-colors uppercase tracking-widest">अभी छोड़ें (Skip for now)</button>
            </div>
          </div>
        )}

        {step === RegistrationStep.REVIEW && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">विवरण की जाँच</h2>
              <p className="text-gray-500">कृपया सुनिश्चित करें कि आपकी जानकारी सही है।</p>
            </div>
            <div className="space-y-4 bg-gray-50 p-8 rounded-[32px] border border-gray-100">
              <div className="flex justify-between items-center py-3 border-b border-gray-200/50">
                <span className="text-sm text-gray-500 font-medium">नाम (Name)</span>
                <span className="font-bold text-gray-900">लघु विक्रेता</span>
              </div>
              <div className="flex justify-between items-center py-3 border-b border-gray-200/50">
                <span className="text-sm text-gray-500 font-medium">मोबाइल (Mobile)</span>
                <span className="font-bold text-gray-900">+91 {mobile}</span>
              </div>
              <div className="flex justify-between items-center py-3 border-b border-gray-200/50">
                <span className="text-sm text-gray-500 font-medium">व्यवसाय (Business)</span>
                <span className="font-bold text-gray-900">{profile.businessType}</span>
              </div>
              <div className="py-3">
                <span className="text-sm text-gray-500 font-medium block mb-2">पता (Address)</span>
                <span className="font-bold text-gray-900 text-sm">{profile.location?.address}</span>
              </div>
            </div>
            <div className="pt-4 space-y-4">
              <div className="flex items-center space-x-3 text-xs text-gray-500 leading-relaxed italic">
                 <ShieldCheck className="w-8 h-8 text-green-600 shrink-0" />
                 मैं प्रमाणित करता हूँ कि दी गई जानकारी सत्य है और मैं उत्तर प्रदेश सरकार के नियमों का पालन करूँगा।
              </div>
              <button 
                onClick={() => onComplete({
                  ...profile as VendorProfile,
                  mobile,
                  name: 'लघु विक्रेता (Vendor)',
                  isVerified: true
                })}
                className="w-full py-6 bg-orange-600 text-white rounded-3xl font-bold text-xl shadow-xl shadow-orange-600/20 hover:scale-[1.02] transition-all"
              >
                अंतिम सबमिट (Final Submit)
              </button>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && (
          <button 
            onClick={prevStep}
            className="mt-8 inline-flex items-center text-gray-400 font-bold text-sm uppercase tracking-widest hover:text-gray-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            पीछे (Back)
          </button>
        )}
      </div>
    </div>
  );
};

export default Registration;

import { GoogleGenAI, Type } from "@google/genai";

// Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getVoiceGuidance = async (step: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide a short, respectful, and helpful instruction in Hindi for a vendor currently at the "${step}" step of registration on the Uttar Pradesh Vendor Portal. Keep it under 20 words. Focus on dignity and ease.`,
      config: {
        systemInstruction: "You are a helpful and respectful administrative assistant for the Government of Uttar Pradesh. Use formal but warm Hindi (Aap format).",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "कृपया अगले चरण पर जाने के लिए अपनी जानकारी दर्ज करें।";
  }
};

export const analyzeEligibility = async (vendorData: any) => {
  try {
    // For complex reasoning tasks like eligibility analysis, use gemini-3-pro-preview.
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Based on this vendor data: ${JSON.stringify(vendorData)}, suggest which government schemes they might be eligible for in Uttar Pradesh. Return names in Hindi.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              schemeName: { type: Type.STRING },
              reason: { type: Type.STRING }
            }
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    return [];
  }
};

