import React, { useState, useEffect } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle } from 'lucide-react';
import { getVoiceGuidance } from '../services/geminiService';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' }
  });

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।');
      return;
    }

    setIsVerifying(true);
    // Simulate API call for OTP
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.BUSINESS_TYPE);
    }, 1500);
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile({
            ...profile,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: "लखनऊ मुख्य बाजार (स्वचालित रूप से निर्धारित)" 
            }
          });
        },
        (geoError) => {
          console.error(geoError);
          setError('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से अपना पता दर्ज करें।');
        },
        { timeout: 10000 }
      );
    } else {
      setError('आपका ब्राउज़र स्थान साझा करने का समर्थन नहीं करता है।');
    }
  };

  const validateAndNext = () => {
    setError(null);
    if (step === RegistrationStep.LOCATION && !profile.location?.address?.trim()) {
      setError('कृपया अपना पता दर्ज करें।');
      return;
    }

    if (step === RegistrationStep.BUSINESS_TYPE) setStep(RegistrationStep.LOCATION);
    else if (step === RegistrationStep.LOCATION) setStep(RegistrationStep.DOCUMENTS);
    else if (step === RegistrationStep.DOCUMENTS) setStep(RegistrationStep.REVIEW);
    else if (step === RegistrationStep.REVIEW) {
      setIsVerifying(true);
      setTimeout(() => {
        onComplete(profile as VendorProfile);
      }, 2000);
    }
  };

  const prevStep = () => {
    setError(null);
    if (step === RegistrationStep.BUSINESS_TYPE) setStep(RegistrationStep.AUTH);
    else if (step === RegistrationStep.LOCATION) setStep(RegistrationStep.BUSINESS_TYPE);
    else if (step === RegistrationStep.DOCUMENTS) setStep(RegistrationStep.LOCATION);
    else if (step === RegistrationStep.REVIEW) setStep(RegistrationStep.DOCUMENTS);
  };

  return (
    <div className="max-w-xl mx-auto px-4 py-12">
      {/* Voice Assistant */}
      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {/* Inline Error Message */}
      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center space-x-3 text-red-700 animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      {/* Progress Line */}
      <div className="flex items-center justify-between mb-12 px-2">
        {Object.values(RegistrationStep).slice(0, 5).map((s, i) => (
          <div key={s} className="flex items-center flex-1 last:flex-none">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all duration-500 ${
              step === s ? 'bg-orange-600 text-white shadow-lg shadow-orange-600/30 scale-110' : 
              i < Object.values(RegistrationStep).indexOf(step) ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-400'
            }`}>
              {i < Object.values(RegistrationStep).indexOf(step) ? <CheckCircle2 className="w-5 h-5" /> : i + 1}
            </div>
            {i < 4 && <div className={`h-1 flex-1 mx-2 rounded-full transition-colors duration-500 ${
              i < Object.values(RegistrationStep).indexOf(step) ? 'bg-green-500' : 'bg-gray-100'
            }`}></div>}
          </div>
        ))}
      </div>

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
