              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">2. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-32 border-2 border-dashed rounded-[32px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-200 bg-gray-50 hover:bg-gray-100'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex items-center space-x-2 text-green-700">
                      <CheckCircle2 className="w-6 h-6" />
