        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in duration-500">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-orange-100 rounded-full"></div>
              <div className="absolute inset-0 w-32 h-32 border-4 border-orange-600 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Fingerprint className="w-12 h-12 text-orange-600 animate-pulse" />
              </div>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-gray-900">DPI सत्यापन जारी है...</h2>
              <p className="text-gray-500 text-sm font-medium px-4">
                हम आपके आधार विवरण और पहचान का मिलान सरकारी डेटाबेस से कर रहे हैं। इसमें कुछ सेकंड लग सकते हैं।
              </p>
            </div>
            <div className="w-full bg-gray-50 p-4 rounded-2xl border border-gray-100 flex items-center justify-center space-x-3 text-xs font-bold text-orange-800 uppercase tracking-widest">
              <ShieldCheck className="w-4 h-4" />
              <span>सुरक्षित सरकारी गेटवे</span>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-8 inline-flex items-center text-gray-400 font-bold text-sm uppercase tracking-widest hover:text-gray-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            पीछे (Back)
          </button>
        )}
      </div>
    </div>
  );
};

