              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-6">
            <h2 className="text-2xl font-bold text-gray-900">विवरण भरें</h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पूर्ण नाम (Full Name)</label>
                <input 
                  type="text"
                  placeholder="आपका नाम दर्ज करें"
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold"
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">आधार नंबर (Aadhar Number)</label>
                <input 
                  type="tel"
                  placeholder="0000 0000 0000"
                  maxLength={12}
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-mono font-bold tracking-[0.2em]"
                  value={profile.aadharNumber}
                  onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">व्यापार की श्रेणी (Category)</label>
                <select 
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold appearance-none"
                  value={profile.businessType}
                  onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                >
                  <option value="">श्रेणी चुनें</option>
                  {BUSINESS_TYPES.map(t => <option key={t.id} value={t.label}>{t.label}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <div className="flex justify-between items-center">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पता (Address)</label>
                  <button onClick={handleLocationDetect} className="text-[10px] font-bold text-orange-600 uppercase flex items-center">
                    <MapPin className="w-3 h-3 mr-1" /> स्थान का पता लगाएं
                  </button>
                </div>
                <textarea 
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 h-24 resize-none font-medium text-sm"
                  placeholder="दुकान/व्यवसाय का पता"
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>

            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError('कृपया सभी आवश्यक जानकारी भरें।');
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
