            >
              <span>पहचान सत्यापित करें</span>
              <Fingerprint className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-8">
            <h2 className="text-2xl font-bold text-gray-900 text-center">डिजिटल सत्यापन</h2>

            <div className="space-y-6">
              {/* Selfie Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">1. अपनी सेल्फी लें</p>
                <div className="relative aspect-[4/3] bg-gray-900 rounded-[32px] overflow-hidden group shadow-inner">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-2">
                      <Camera className="w-12 h-12" />
                      <span className="font-bold text-xs uppercase tracking-widest">कैमरा चालू करें</span>
                    </button>
                  ) : selfie ? (
                    <>
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <button onClick={() => {setSelfie(null); startCamera();}} className="absolute bottom-4 right-4 bg-white/20 backdrop-blur-md p-3 rounded-full text-white">
                        <Camera className="w-5 h-5" />
                      </button>
                    </>
                  ) : (
                    <>
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                      <button onClick={captureSelfie} className="absolute bottom-6 left-1/2 -translate-x-1/2 w-16 h-16 bg-white rounded-full border-4 border-white/30 flex items-center justify-center shadow-lg active:scale-90 transition-transform">
                        <div className="w-12 h-12 rounded-full border-2 border-orange-600"></div>
                      </button>
                    </>
                  )}
                  <canvas ref={canvasRef} className="hidden" />
                </div>
              </div>

              {/* Aadhar Upload Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">2. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-32 border-2 border-dashed rounded-[32px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-200 bg-gray-50 hover:bg-gray-100'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex items-center space-x-2 text-green-700">
                      <CheckCircle2 className="w-6 h-6" />
                      <span className="font-bold">आधार स्कैन प्राप्त हुआ</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center text-gray-400 space-y-1">
                      <Upload className="w-6 h-6" />
                      <span className="text-[10px] font-bold uppercase tracking-widest">फाइल चुनें या स्कैन करें</span>
                    </div>
                  )}
                </label>
              </div>
            </div>

            <button 
              onClick={runDPIVerification}
              disabled={!selfie || !aadharScan}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold flex items-center justify-center space-x-2 disabled:opacity-30 transition-all"
            >
              <span>सत्यापन के लिए सबमिट करें</span>
              <ShieldCheck className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in duration-500">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-orange-100 rounded-full"></div>
              <div className="absolute inset-0 w-32 h-32 border-4 border-orange-600 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Fingerprint className="w-12 h-12 text-orange-600 animate-pulse" />
              </div>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-gray-900">DPI सत्यापन जारी है...</h2>
              <p className="text-gray-500 text-sm font-medium px-4">
                हम आपके आधार विवरण और पहचान का मिलान सरकारी डेटाबेस से कर रहे हैं। इसमें कुछ सेकंड लग सकते हैं।
              </p>
            </div>
            <div className="w-full bg-gray-50 p-4 rounded-2xl border border-gray-100 flex items-center justify-center space-x-3 text-xs font-bold text-orange-800 uppercase tracking-widest">
              <ShieldCheck className="w-4 h-4" />
              <span>सुरक्षित सरकारी गेटवे</span>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-8 inline-flex items-center text-gray-400 font-bold text-sm uppercase tracking-widest hover:text-gray-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            पीछे (Back)
          </button>
        )}
      </div>
    </div>
  );
};

export default Registration;

import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [isListeningAddress, setIsListeningAddress] = useState(false);
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' }
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।');
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      setError('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।');
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        setSelfie(dataUrl);
        // Stop stream
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") + "लखनऊ मुख्य बाजार (स्वचालित रूप से निर्धारित)" 
            }
          }));
        },
        () => setError('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से अपना पता दर्ज करें।'),
        { timeout: 10000 }
      );
    }
  };

  const toggleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('आपका ब्राउज़र वॉयस इनपुट का समर्थन नहीं करता है।');
      return;
    }

    if (isListeningAddress) {
      setIsListeningAddress(false);
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'hi-IN'; // Default to Hindi, works well for mixed input too
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListeningAddress(true);
      setError(null);
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setProfile(prev => ({
        ...prev,
        location: {
          ...prev.location!,
          address: (prev.location?.address ? prev.location.address + " " : "") + transcript
        }
      }));
      setIsListeningAddress(false);
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      setIsListeningAddress(false);
      if (event.error === 'no-speech') {
        setError('कोई आवाज़ नहीं सुनी गई। कृपया फिर से कोशिश करें।');
      } else {
        setError('वॉयस इनपुट में समस्या आई।');
      }
    };

    recognition.onend = () => {
      setIsListeningAddress(false);
    };

    recognition.start();
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);
    setTimeout(() => {
      if (result.success) {
        onComplete({ ...profile, mobile, selfie, aadharScan, isVerified: true } as VendorProfile);
      } else {
        setError(result.message || 'सत्यापन विफल। कृपया पुनः प्रयास करें।');
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 3000);
  };

  return (
    <div className="max-w-xl mx-auto px-4 py-12">
      {/* Voice Assistant */}
      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center space-x-3 text-red-700 animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700 ml-1">मोबाइल नंबर</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000-00000"
                    maxLength={10}
                    className="w-full pl-14 pr-4 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 transition-all text-xl tracking-widest font-bold"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2">
                {isVerifying ? <Loader2 className="w-6 h-6 animate-spin" /> : <><span>OTP भेजें</span> <ArrowRight className="w-5 h-5" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-6">
            <h2 className="text-2xl font-bold text-gray-900">विवरण भरें</h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पूर्ण नाम (Full Name)</label>
                <input 
                  type="text"
                  placeholder="आपका नाम दर्ज करें"
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold"
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">आधार नंबर (Aadhar Number)</label>
                <input 
                  type="tel"
                  placeholder="0000 0000 0000"
                  maxLength={12}
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-mono font-bold tracking-[0.2em]"
                  value={profile.aadharNumber}
                  onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">व्यापार की श्रेणी (Category)</label>
                <select 
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold appearance-none"
                  value={profile.businessType}
                  onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                >
                  <option value="">श्रेणी चुनें</option>
                  {BUSINESS_TYPES.map(t => <option key={t.id} value={t.label}>{t.label}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पता (Address)</label>
                  <div className="flex space-x-3">
                    <button 
                      onClick={toggleVoiceInput} 
                      className={`text-[10px] font-bold uppercase flex items-center transition-all ${isListeningAddress ? 'text-red-600 animate-pulse' : 'text-indigo-600 hover:text-indigo-800'}`}
                    >
                      {isListeningAddress ? <MicOff className="w-3 h-3 mr-1" /> : <Mic className="w-3 h-3 mr-1" />}
                      {isListeningAddress ? 'सुन रहा हूँ...' : 'बोलें (Speak)'}
                    </button>
                    <button onClick={handleLocationDetect} className="text-[10px] font-bold text-orange-600 uppercase flex items-center hover:text-orange-800">
                      <MapPin className="w-3 h-3 mr-1" /> स्थान चुनें
                    </button>
                  </div>
                </div>
                <textarea 
                  className={`w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 transition-all h-24 resize-none font-medium text-sm ${isListeningAddress ? 'ring-2 ring-indigo-500 bg-indigo-50/30 shadow-inner' : 'focus:ring-orange-600'}`}
                  placeholder={isListeningAddress ? "सुन रहा हूँ... कृपया अपना पता बोलें" : "दुकान/व्यवसाय का पता दर्ज करें या ऊपर 'बोलें' बटन दबाएं"}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>

            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError('कृपया सभी आवश्यक जानकारी भरें।');
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold mt-4 flex items-center justify-center space-x-2"
            >
              <span>पहचान सत्यापित करें</span>
              <Fingerprint className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-8">
            <h2 className="text-2xl font-bold text-gray-900 text-center">डिजिटल सत्यापन</h2>

            <div className="space-y-6">
              {/* Selfie Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">1. अपनी सेल्फी लें</p>
                <div className="relative aspect-[4/3] bg-gray-900 rounded-[32px] overflow-hidden group shadow-inner">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-2">
                      <Camera className="w-12 h-12" />
                      <span className="font-bold text-xs uppercase tracking-widest">कैमरा चालू करें</span>
                    </button>
                  ) : selfie ? (
                    <>
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <button onClick={() => {setSelfie(null); startCamera();}} className="absolute bottom-4 right-4 bg-white/20 backdrop-blur-md p-3 rounded-full text-white">
                        <Camera className="w-5 h-5" />
                      </button>
                    </>
                  ) : (
                    <>
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                      <button onClick={captureSelfie} className="absolute bottom-6 left-1/2 -translate-x-1/2 w-16 h-16 bg-white rounded-full border-4 border-white/30 flex items-center justify-center shadow-lg active:scale-90 transition-transform">
                        <div className="w-12 h-12 rounded-full border-2 border-orange-600"></div>
                      </button>
                    </>
                  )}
                  <canvas ref={canvasRef} className="hidden" />
                </div>
              </div>

              {/* Aadhar Upload Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">2. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-32 border-2 border-dashed rounded-[32px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-200 bg-gray-50 hover:bg-gray-100'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex items-center space-x-2 text-green-700">
                      <CheckCircle2 className="w-6 h-6" />
                      <span className="font-bold">आधार स्कैन प्राप्त हुआ</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center text-gray-400 space-y-1">
                      <Upload className="w-6 h-6" />
                      <span className="text-[10px] font-bold uppercase tracking-widest">फाइल चुनें या स्कैन करें</span>
                    </div>
                  )}
                </label>
              </div>
            </div>

            <button 
              onClick={runDPIVerification}
              disabled={!selfie || !aadharScan}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold flex items-center justify-center space-x-2 disabled:opacity-30 transition-all"
            >
              <span>सत्यापन के लिए सबमिट करें</span>
              <ShieldCheck className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in duration-500">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-orange-100 rounded-full"></div>
              <div className="absolute inset-0 w-32 h-32 border-4 border-orange-600 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Fingerprint className="w-12 h-12 text-orange-600 animate-pulse" />
              </div>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-gray-900">DPI सत्यापन जारी है...</h2>
              <p className="text-gray-500 text-sm font-medium px-4">
                हम आपके आधार विवरण और पहचान का मिलान सरकारी डेटाबेस से कर रहे हैं। इसमें कुछ सेकंड लग सकते हैं।
              </p>
            </div>
            <div className="w-full bg-gray-50 p-4 rounded-2xl border border-gray-100 flex items-center justify-center space-x-3 text-xs font-bold text-orange-800 uppercase tracking-widest">
              <ShieldCheck className="w-4 h-4" />
              <span>सुरक्षित सरकारी गेटवे</span>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-8 inline-flex items-center text-gray-400 font-bold text-sm uppercase tracking-widest hover:text-gray-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            पीछे (Back)
          </button>
        )}
      </div>
    </div>
  );
};

export default Registration;

import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff, RefreshCcw } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [isListeningAddress, setIsListeningAddress] = useState(false);
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' }
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।');
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      setError('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।');
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        setSelfie(dataUrl);
        // Stop stream
        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") + "लखनऊ मुख्य बाजार (स्वचालित रूप से निर्धारित)" 
            }
          }));
        },
        () => setError('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से अपना पता दर्ज करें।'),
        { timeout: 10000 }
      );
    }
  };

  const toggleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('आपका ब्राउज़र वॉयस इनपुट का समर्थन नहीं करता है।');
      return;
    }

    if (isListeningAddress) {
      setIsListeningAddress(false);
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'hi-IN';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListeningAddress(true);
      setError(null);
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setProfile(prev => ({
        ...prev,
        location: {
          ...prev.location!,
          address: (prev.location?.address ? prev.location.address + " " : "") + transcript
        }
      }));
      setIsListeningAddress(false);
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      setIsListeningAddress(false);
      if (event.error === 'no-speech') {
        setError('कोई आवाज़ नहीं सुनी गई। कृपया फिर से कोशिश करें।');
      } else {
        setError('वॉयस इनपुट में समस्या आई।');
      }
    };

    recognition.onend = () => {
      setIsListeningAddress(false);
    };

    recognition.start();
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);
    setTimeout(() => {
      if (result.success) {
        onComplete({ ...profile, mobile, selfie, aadharScan, isVerified: true } as VendorProfile);
      } else {
        setError(result.message || 'सत्यापन विफल। कृपया पुनः प्रयास करें।');
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 3000);
  };

  return (
    <div className="max-w-xl mx-auto px-4 py-12">
      {/* Voice Assistant */}
      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center space-x-3 text-red-700 animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700 ml-1">मोबाइल नंबर</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000-00000"
                    maxLength={10}
                    className="w-full pl-14 pr-4 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 transition-all text-xl tracking-widest font-bold"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2">
                {isVerifying ? <Loader2 className="w-6 h-6 animate-spin" /> : <><span>OTP भेजें</span> <ArrowRight className="w-5 h-5" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-6">
            <h2 className="text-2xl font-bold text-gray-900">विवरण भरें</h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पूर्ण नाम (Full Name)</label>
                <input 
                  type="text"
                  placeholder="आपका नाम दर्ज करें"
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold"
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">आधार नंबर (Aadhar Number)</label>
                <input 
                  type="tel"
                  placeholder="0000 0000 0000"
                  maxLength={12}
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-mono font-bold tracking-[0.2em]"
                  value={profile.aadharNumber}
                  onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">व्यापार की श्रेणी (Category)</label>
                <select 
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold appearance-none"
                  value={profile.businessType}
                  onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                >
                  <option value="">श्रेणी चुनें</option>
                  {BUSINESS_TYPES.map(t => <option key={t.id} value={t.label}>{t.label}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पता (Address)</label>
                  <div className="flex space-x-3">
                    <button 
                      onClick={toggleVoiceInput} 
                      className={`text-[10px] font-bold uppercase flex items-center transition-all ${isListeningAddress ? 'text-red-600 animate-pulse' : 'text-indigo-600 hover:text-indigo-800'}`}
                    >
                      {isListeningAddress ? <MicOff className="w-3 h-3 mr-1" /> : <Mic className="w-3 h-3 mr-1" />}
                      {isListeningAddress ? 'सुन रहा हूँ...' : 'बोलें (Speak)'}
                    </button>
                    <button onClick={handleLocationDetect} className="text-[10px] font-bold text-orange-600 uppercase flex items-center hover:text-orange-800">
                      <MapPin className="w-3 h-3 mr-1" /> स्थान चुनें
                    </button>
                  </div>
                </div>
                <textarea 
                  className={`w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 transition-all h-24 resize-none font-medium text-sm ${isListeningAddress ? 'ring-2 ring-indigo-500 bg-indigo-50/30 shadow-inner' : 'focus:ring-orange-600'}`}
                  placeholder={isListeningAddress ? "सुन रहा हूँ... कृपया अपना पता बोलें" : "दुकान/व्यवसाय का पता दर्ज करें या ऊपर 'बोलें' बटन दबाएं"}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>

            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError('कृपया सभी आवश्यक जानकारी भरें।');
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold mt-4 flex items-center justify-center space-x-2"
            >
              <span>पहचान सत्यापित करें</span>
              <Fingerprint className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-8">
            <h2 className="text-2xl font-bold text-gray-900 text-center">डिजिटल सत्यापन</h2>

            <div className="space-y-6">
              {/* Selfie Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">1. अपनी सेल्फी लें</p>
                <div className="relative aspect-[4/3] bg-gray-900 rounded-[32px] overflow-hidden group shadow-inner">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-2 hover:bg-gray-800 transition-colors">
                      <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-2">
                        <Camera className="w-8 h-8 text-white" />
                      </div>
                      <span className="font-bold text-xs uppercase tracking-widest text-white/80">कैमरा चालू करें</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full animate-in zoom-in-105 duration-500">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <div className="absolute top-4 left-4 bg-green-500 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center shadow-lg">
                        <CheckCircle2 className="w-3 h-3 mr-1" /> फोटो सुरक्षित है
                      </div>
                      <button 
                        onClick={() => {setSelfie(null); startCamera();}} 
                        className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-2xl font-bold text-sm flex items-center space-x-2 shadow-2xl hover:bg-gray-50 active:scale-95 transition-all"
                      >
                        <RefreshCcw className="w-4 h-4 text-orange-600" />
                        <span>फिर से लें (Retake)</span>
                      </button>
                    </div>
                  ) : (
                    <>
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                      <div className="absolute inset-0 border-[20px] border-black/40 pointer-events-none flex items-center justify-center">
                         <div className="w-48 h-64 border-2 border-white/50 rounded-full border-dashed"></div>
                      </div>
                      <button onClick={captureSelfie} className="absolute bottom-6 left-1/2 -translate-x-1/2 w-16 h-16 bg-white rounded-full border-4 border-white/30 flex items-center justify-center shadow-lg active:scale-90 transition-transform">
                        <div className="w-12 h-12 rounded-full border-2 border-orange-600"></div>
                      </button>
                      <p className="absolute top-6 left-1/2 -translate-x-1/2 text-white text-[10px] font-bold uppercase tracking-widest text-center w-full px-4 drop-shadow-md">चेहरा सर्कल के बीच में रखें</p>
                    </>
                  )}
                  <canvas ref={canvasRef} className="hidden" />
                </div>
              </div>

              {/* Aadhar Upload Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">2. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-32 border-2 border-dashed rounded-[32px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-200 bg-gray-50 hover:bg-gray-100'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-2 animate-in fade-in">
                      <div className="flex items-center space-x-2 text-green-700">
                        <CheckCircle2 className="w-6 h-6" />
                        <span className="font-bold">आधार स्कैन प्राप्त हुआ</span>
                      </div>
                      <span className="text-[10px] font-bold text-green-600/60 uppercase tracking-widest underline">बदलने के लिए यहाँ दबाएं</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center text-gray-400 space-y-1">
                      <Upload className="w-6 h-6" />
                      <span className="text-[10px] font-bold uppercase tracking-widest text-center px-4 leading-tight">फाइल चुनें या आधार की फोटो अपलोड करें</span>
                    </div>
                  )}
                </label>
              </div>
            </div>

            <button 
              onClick={runDPIVerification}
              disabled={!selfie || !aadharScan}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold flex items-center justify-center space-x-2 disabled:opacity-30 transition-all shadow-xl shadow-orange-600/10"
            >
              <span>सत्यापन के लिए सबमिट करें</span>
              <ShieldCheck className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in duration-500">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-orange-100 rounded-full"></div>
              <div className="absolute inset-0 w-32 h-32 border-4 border-orange-600 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Fingerprint className="w-12 h-12 text-orange-600 animate-pulse" />
              </div>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-gray-900">DPI सत्यापन जारी है...</h2>
              <p className="text-gray-500 text-sm font-medium px-4">
                हम आपके आधार विवरण और पहचान का मिलान सरकारी डेटाबेस से कर रहे हैं। इसमें कुछ सेकंड लग सकते हैं।
              </p>
            </div>
            <div className="w-full bg-gray-50 p-4 rounded-2xl border border-gray-100 flex items-center justify-center space-x-3 text-xs font-bold text-orange-800 uppercase tracking-widest">
              <ShieldCheck className="w-4 h-4" />
              <span>सुरक्षित सरकारी गेटवे</span>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-8 inline-flex items-center text-gray-400 font-bold text-sm uppercase tracking-widest hover:text-gray-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            पीछे (Back)
          </button>
        )}
      </div>
    </div>
  );
};

export default Registration;

import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff, RefreshCcw, Circle } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [isListeningAddress, setIsListeningAddress] = useState(false);
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' }
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।');
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      setError('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।');
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        // Mirror the capture to match the mirrored preview
        context.translate(canvasRef.current.width, 0);
        context.scale(-1, 1);
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        setSelfie(dataUrl);

        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") + "लखनऊ मुख्य बाजार (स्वचालित रूप से निर्धारित)" 
            }
          }));
        },
        () => setError('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से अपना पता दर्ज करें।'),
        { timeout: 10000 }
      );
    }
  };

  const toggleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('आपका ब्राउज़र वॉयस इनपुट का समर्थन नहीं करता है।');
      return;
    }

    if (isListeningAddress) {
      setIsListeningAddress(false);
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'hi-IN';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListeningAddress(true);
      setError(null);
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setProfile(prev => ({
        ...prev,
        location: {
          ...prev.location!,
          address: (prev.location?.address ? prev.location.address + " " : "") + transcript
        }
      }));
      setIsListeningAddress(false);
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      setIsListeningAddress(false);
      if (event.error === 'no-speech') {
        setError('कोई आवाज़ नहीं सुनी गई। कृपया फिर से कोशिश करें।');
      } else {
        setError('वॉयस इनपुट में समस्या आई।');
      }
    };

    recognition.onend = () => {
      setIsListeningAddress(false);
    };

    recognition.start();
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);
    setTimeout(() => {
      if (result.success) {
        onComplete({ ...profile, mobile, selfie, aadharScan, isVerified: true } as VendorProfile);
      } else {
        setError(result.message || 'सत्यापन विफल। कृपया पुनः प्रयास करें।');
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 3000);
  };

  return (
    <div className="max-w-xl mx-auto px-4 py-12">
      {/* Voice Assistant */}
      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center space-x-3 text-red-700 animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700 ml-1">मोबाइल नंबर</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000-00000"
                    maxLength={10}
                    className="w-full pl-14 pr-4 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 transition-all text-xl tracking-widest font-bold"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2">
                {isVerifying ? <Loader2 className="w-6 h-6 animate-spin" /> : <><span>OTP भेजें</span> <ArrowRight className="w-5 h-5" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-6">
            <h2 className="text-2xl font-bold text-gray-900">विवरण भरें</h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पूर्ण नाम (Full Name)</label>
                <input 
                  type="text"
                  placeholder="आपका नाम दर्ज करें"
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold"
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">आधार नंबर (Aadhar Number)</label>
                <input 
                  type="tel"
                  placeholder="0000 0000 0000"
                  maxLength={12}
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-mono font-bold tracking-[0.2em]"
                  value={profile.aadharNumber}
                  onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">व्यापार की श्रेणी (Category)</label>
                <select 
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold appearance-none"
                  value={profile.businessType}
                  onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                >
                  <option value="">श्रेणी चुनें</option>
                  {BUSINESS_TYPES.map(t => <option key={t.id} value={t.label}>{t.label}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पता (Address)</label>
                  <div className="flex space-x-3">
                    <button 
                      onClick={toggleVoiceInput} 
                      className={`text-[10px] font-bold uppercase flex items-center transition-all ${isListeningAddress ? 'text-red-600 animate-pulse' : 'text-indigo-600 hover:text-indigo-800'}`}
                    >
                      {isListeningAddress ? <MicOff className="w-3 h-3 mr-1" /> : <Mic className="w-3 h-3 mr-1" />}
                      {isListeningAddress ? 'सुन रहा हूँ...' : 'बोलें (Speak)'}
                    </button>
                    <button onClick={handleLocationDetect} className="text-[10px] font-bold text-orange-600 uppercase flex items-center hover:text-orange-800">
                      <MapPin className="w-3 h-3 mr-1" /> स्थान चुनें
                    </button>
                  </div>
                </div>
                <textarea 
                  className={`w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 transition-all h-24 resize-none font-medium text-sm ${isListeningAddress ? 'ring-2 ring-indigo-500 bg-indigo-50/30 shadow-inner' : 'focus:ring-orange-600'}`}
                  placeholder={isListeningAddress ? "सुन रहा हूँ... कृपया अपना पता बोलें" : "दुकान/व्यवसाय का पता दर्ज करें या ऊपर 'बोलें' बटन दबाएं"}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>

            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError('कृपया सभी आवश्यक जानकारी भरें।');
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold mt-4 flex items-center justify-center space-x-2"
            >
              <span>पहचान सत्यापित करें</span>
              <Fingerprint className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-8">
            <h2 className="text-2xl font-bold text-gray-900 text-center">डिजिटल सत्यापन</h2>

            <div className="space-y-6">
              {/* Selfie Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">1. अपनी सेल्फी लें</p>
                <div className="relative aspect-[4/3] bg-gray-900 rounded-[32px] overflow-hidden group shadow-inner">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-2 hover:bg-gray-800 transition-colors">
                      <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-2">
                        <Camera className="w-8 h-8 text-white" />
                      </div>
                      <span className="font-bold text-xs uppercase tracking-widest text-white/80">कैमरा चालू करें</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full animate-in zoom-in-105 duration-500">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <div className="absolute top-4 left-4 bg-green-500 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center shadow-lg">
                        <CheckCircle2 className="w-3 h-3 mr-1" /> फोटो सुरक्षित है
                      </div>
                      <button 
                        onClick={() => {setSelfie(null); startCamera();}} 
                        className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-2xl font-bold text-sm flex items-center space-x-2 shadow-2xl hover:bg-gray-50 active:scale-95 transition-all"
                      >
                        <RefreshCcw className="w-4 h-4 text-orange-600" />
                        <span>फिर से लें (Retake)</span>
                      </button>
                    </div>
                  ) : (
                    <>
                      {/* Mirrored Live Feed for Selfie UX */}
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />

                      {/* Live Indicator Overlay */}
                      <div className="absolute top-4 left-4 flex items-center space-x-2 bg-black/40 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
                         <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                         <span className="text-[10px] font-bold text-white uppercase tracking-widest">LIVE FEED</span>
                      </div>

                      {/* Framing Guide */}
                      <div className="absolute inset-0 border-[20px] border-black/40 pointer-events-none flex items-center justify-center">
                         <div className="w-48 h-64 border-2 border-white/50 rounded-full border-dashed animate-pulse duration-[2000ms]"></div>
                      </div>

                      {/* DPI Style Scanning Line Overlay */}
                      <div className="absolute inset-x-0 h-px bg-orange-500/50 shadow-[0_0_15px_rgba(249,115,22,0.5)] animate-scan pointer-events-none"></div>

                      <button onClick={captureSelfie} className="absolute bottom-6 left-1/2 -translate-x-1/2 w-20 h-20 bg-white rounded-full border-4 border-white/30 flex items-center justify-center shadow-2xl active:scale-90 transition-transform group overflow-hidden">
                        <div className="w-16 h-16 rounded-full border-2 border-orange-600 flex items-center justify-center transition-all group-hover:bg-orange-50">
                           <Camera className="w-6 h-6 text-orange-600" />
                        </div>
                      </button>

                      <p className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white/30 text-[40px] font-bold opacity-10 pointer-events-none select-none">UP GOVT</p>
                      <p className="absolute bottom-28 left-1/2 -translate-x-1/2 text-white text-[10px] font-bold uppercase tracking-widest text-center w-full px-4 drop-shadow-md">अपना चेहरा बीच में लाएं</p>
                    </>
                  )}
                  <canvas ref={canvasRef} className="hidden" />
                </div>
              </div>

              {/* Aadhar Upload Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">2. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-32 border-2 border-dashed rounded-[32px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-200 bg-gray-50 hover:bg-gray-100'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-2 animate-in fade-in">
                      <div className="flex items-center space-x-2 text-green-700">
                        <CheckCircle2 className="w-6 h-6" />
                        <span className="font-bold">आधार स्कैन प्राप्त हुआ</span>
                      </div>
                      <span className="text-[10px] font-bold text-green-600/60 uppercase tracking-widest underline">बदलने के लिए यहाँ दबाएं</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center text-gray-400 space-y-1">
                      <Upload className="w-6 h-6" />
                      <span className="text-[10px] font-bold uppercase tracking-widest text-center px-4 leading-tight">फाइल चुनें या आधार की फोटो अपलोड करें</span>
                    </div>
                  )}
                </label>
              </div>
            </div>

            <button 
              onClick={runDPIVerification}
              disabled={!selfie || !aadharScan}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold flex items-center justify-center space-x-2 disabled:opacity-30 transition-all shadow-xl shadow-orange-600/10"
            >
              <span>सत्यापन के लिए सबमिट करें</span>
              <ShieldCheck className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in duration-500">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-orange-100 rounded-full"></div>
              <div className="absolute inset-0 w-32 h-32 border-4 border-orange-600 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Fingerprint className="w-12 h-12 text-orange-600 animate-pulse" />
              </div>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-gray-900">DPI सत्यापन जारी है...</h2>
              <p className="text-gray-500 text-sm font-medium px-4">
                हम आपके आधार विवरण और पहचान का मिलान सरकारी डेटाबेस से कर रहे हैं। इसमें कुछ सेकंड लग सकते हैं।
              </p>
            </div>
            <div className="w-full bg-gray-50 p-4 rounded-2xl border border-gray-100 flex items-center justify-center space-x-3 text-xs font-bold text-orange-800 uppercase tracking-widest">
              <ShieldCheck className="w-4 h-4" />
              <span>सुरक्षित सरकारी गेटवे</span>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-8 inline-flex items-center text-gray-400 font-bold text-sm uppercase tracking-widest hover:text-gray-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            पीछे (Back)
          </button>
        )}
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 10%; }
          100% { top: 90%; }
        }
        .animate-scan {
          position: absolute;
          animation: scan 3s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default Registration;

export enum RegistrationStep {
  AUTH = 'AUTH',
  PROFILE = 'PROFILE',
  VERIFY_IDENTITY = 'VERIFY_IDENTITY',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED'
}

export interface ActivityLog {
  date: string;
  action: string;
}

export interface VendorProfile {
  id?: string;
  name: string;
  mobile: string;
  aadharNumber: string;
  businessType: string;
  location: {
    lat: number;
    lng: number;
    address: string;
  };
  vendingType: 'fixed' | 'mobile' | 'seasonal';
  isVerified: boolean;
  selfie?: string;
  aadharScan?: string;
  activeSchemes?: string[];
  loanStatus?: 'eligible' | 'applied' | 'none';
  activityHistory?: ActivityLog[];
}

export interface Scheme {
  id: string;
  title: string;
  titleHi: string;
  description: string;
  descriptionHi: string;
  icon: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff, RefreshCcw, Circle } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [isListeningAddress, setIsListeningAddress] = useState(false);
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' },
    activeSchemes: [],
    loanStatus: 'none',
    activityHistory: []
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।');
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      setError('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।');
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        // Mirror the capture to match the mirrored preview
        context.translate(canvasRef.current.width, 0);
        context.scale(-1, 1);
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        setSelfie(dataUrl);

        const stream = videoRef.current.srcObject as MediaStream;
        stream.getTracks().forEach(track => track.stop());
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") + "लखनऊ मुख्य बाजार (स्वचालित रूप से निर्धारित)" 
            }
          }));
        },
        () => setError('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से अपना पता दर्ज करें।'),
        { timeout: 10000 }
      );
    }
  };

  const toggleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('आपका ब्राउज़र वॉयस इनपुट का समर्थन नहीं करता है।');
      return;
    }

    if (isListeningAddress) {
      setIsListeningAddress(false);
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'hi-IN';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListeningAddress(true);
      setError(null);
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setProfile(prev => ({
        ...prev,
        location: {
          ...prev.location!,
          address: (prev.location?.address ? prev.location.address + " " : "") + transcript
        }
      }));
      setIsListeningAddress(false);
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      setIsListeningAddress(false);
      if (event.error === 'no-speech') {
        setError('कोई आवाज़ नहीं सुनी गई। कृपया फिर से कोशिश करें।');
      } else {
        setError('वॉयस इनपुट में समस्या आई।');
      }
    };

    recognition.onend = () => {
      setIsListeningAddress(false);
    };

    recognition.start();
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);
    setTimeout(() => {
      if (result.success) {
        const finalProfile = { 
          ...profile, 
          mobile, 
          selfie, 
          aadharScan, 
          isVerified: true,
          activeSchemes: ['PM SVANidhi'],
          loanStatus: 'eligible' as const,
          activityHistory: [{ date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }), action: 'Registration Completed' }]
        };
        onComplete(finalProfile as VendorProfile);
      } else {
        setError(result.message || 'सत्यापन विफल। कृपया पुनः प्रयास करें।');
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 3000);
  };

  return (
    <div className="max-w-xl mx-auto px-4 py-12">
      {/* Voice Assistant */}
      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center space-x-3 text-red-700 animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700 ml-1">मोबाइल नंबर</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000-00000"
                    maxLength={10}
                    className="w-full pl-14 pr-4 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 transition-all text-xl tracking-widest font-bold"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2">
                {isVerifying ? <Loader2 className="w-6 h-6 animate-spin" /> : <><span>OTP भेजें</span> <ArrowRight className="w-5 h-5" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-6">
            <h2 className="text-2xl font-bold text-gray-900">विवरण भरें</h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पूर्ण नाम (Full Name)</label>
                <input 
                  type="text"
                  placeholder="आपका नाम दर्ज करें"
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold"
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">आधार नंबर (Aadhar Number)</label>
                <input 
                  type="tel"
                  placeholder="0000 0000 0000"
                  maxLength={12}
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-mono font-bold tracking-[0.2em]"
                  value={profile.aadharNumber}
                  onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">व्यापार की श्रेणी (Category)</label>
                <select 
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold appearance-none"
                  value={profile.businessType}
                  onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                >
                  <option value="">श्रेणी चुनें</option>
                  {BUSINESS_TYPES.map(t => <option key={t.id} value={t.label}>{t.label}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पता (Address)</label>
                  <div className="flex space-x-3">
                    <button 
                      onClick={toggleVoiceInput} 
                      className={`text-[10px] font-bold uppercase flex items-center transition-all ${isListeningAddress ? 'text-red-600 animate-pulse' : 'text-indigo-600 hover:text-indigo-800'}`}
                    >
                      {isListeningAddress ? <MicOff className="w-3 h-3 mr-1" /> : <Mic className="w-3 h-3 mr-1" />}
                      {isListeningAddress ? 'सुन रहा हूँ...' : 'बोलें (Speak)'}
                    </button>
                    <button onClick={handleLocationDetect} className="text-[10px] font-bold text-orange-600 uppercase flex items-center hover:text-orange-800">
                      <MapPin className="w-3 h-3 mr-1" /> स्थान चुनें
                    </button>
                  </div>
                </div>
                <textarea 
                  className={`w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 transition-all h-24 resize-none font-medium text-sm ${isListeningAddress ? 'ring-2 ring-indigo-500 bg-indigo-50/30 shadow-inner' : 'focus:ring-orange-600'}`}
                  placeholder={isListeningAddress ? "सुन रहा हूँ... कृपया अपना पता बोलें" : "दुकान/व्यवसाय का पता दर्ज करें या ऊपर 'बोलें' बटन दबाएं"}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>

            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError('कृपया सभी आवश्यक जानकारी भरें।');
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold mt-4 flex items-center justify-center space-x-2"
            >
              <span>पहचान सत्यापित करें</span>
              <Fingerprint className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-8">
            <h2 className="text-2xl font-bold text-gray-900 text-center">डिजिटल सत्यापन</h2>

            <div className="space-y-6">
              {/* Selfie Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">1. अपनी सेल्फी लें</p>
                <div className="relative aspect-[4/3] bg-gray-900 rounded-[32px] overflow-hidden group shadow-inner">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-2 hover:bg-gray-800 transition-colors">
                      <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-2">
                        <Camera className="w-8 h-8 text-white" />
                      </div>
                      <span className="font-bold text-xs uppercase tracking-widest text-white/80">कैमरा चालू करें</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full animate-in zoom-in-105 duration-500">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <div className="absolute top-4 left-4 bg-green-500 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center shadow-lg">
                        <CheckCircle2 className="w-3 h-3 mr-1" /> फोटो सुरक्षित है
                      </div>
                      <button 
                        onClick={() => {setSelfie(null); startCamera();}} 
                        className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-2xl font-bold text-sm flex items-center space-x-2 shadow-2xl hover:bg-gray-50 active:scale-95 transition-all"
                      >
                        <RefreshCcw className="w-4 h-4 text-orange-600" />
                        <span>फिर से लें (Retake)</span>
                      </button>
                    </div>
                  ) : (
                    <>
                      {/* Mirrored Live Feed for Selfie UX */}
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />

                      {/* Live Indicator Overlay */}
                      <div className="absolute top-4 left-4 flex items-center space-x-2 bg-black/40 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
                         <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                         <span className="text-[10px] font-bold text-white uppercase tracking-widest">LIVE FEED</span>
                      </div>

                      {/* Framing Guide */}
                      <div className="absolute inset-0 border-[20px] border-black/40 pointer-events-none flex items-center justify-center">
                         <div className="w-48 h-64 border-2 border-white/50 rounded-full border-dashed animate-pulse duration-[2000ms]"></div>
                      </div>

                      {/* DPI Style Scanning Line Overlay */}
                      <div className="absolute inset-x-0 h-px bg-orange-500/50 shadow-[0_0_15px_rgba(249,115,22,0.5)] animate-scan pointer-events-none"></div>

                      {/* ENHANCED CAPTURE BUTTON WITH MINI PREVIEW */}
                      <button 
                        onClick={captureSelfie} 
                        className="absolute bottom-6 left-1/2 -translate-x-1/2 w-24 h-24 bg-white/20 backdrop-blur-xl rounded-full border-4 border-white/50 flex items-center justify-center shadow-2xl active:scale-90 transition-all group overflow-hidden"
                      >
                        {/* Inner Mini Live Preview */}
                        <div className="absolute inset-1 rounded-full overflow-hidden border-2 border-orange-600">
                           <video 
                              autoPlay 
                              playsInline 
                              muted 
                              className="w-full h-full object-cover scale-x-[-1] opacity-80"
                              ref={(el) => { if(el && videoRef.current) el.srcObject = videoRef.current.srcObject; }}
                           />
                           <div className="absolute inset-0 bg-orange-600/10 group-hover:bg-transparent transition-colors"></div>
                        </div>
                        <Camera className="w-8 h-8 text-white relative z-10 drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)]" />
                      </button>

                      <p className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white/30 text-[40px] font-bold opacity-10 pointer-events-none select-none">UP GOVT</p>
                      <p className="absolute bottom-32 left-1/2 -translate-x-1/2 text-white text-[10px] font-bold uppercase tracking-widest text-center w-full px-4 drop-shadow-md">बटन के अंदर अपना चेहरा देखें और क्लिक करें</p>
                    </>
                  )}
                  <canvas ref={canvasRef} className="hidden" />
                </div>
              </div>

              {/* Aadhar Upload Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">2. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-32 border-2 border-dashed rounded-[32px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-200 bg-gray-50 hover:bg-gray-100'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-2 animate-in fade-in">
                      <div className="flex items-center space-x-2 text-green-700">
                        <CheckCircle2 className="w-6 h-6" />
                        <span className="font-bold">आधार स्कैन प्राप्त हुआ</span>
                      </div>
                      <span className="text-[10px] font-bold text-green-600/60 uppercase tracking-widest underline">बदलने के लिए यहाँ दबाएं</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center text-gray-400 space-y-1">
                      <Upload className="w-6 h-6" />
                      <span className="text-[10px] font-bold uppercase tracking-widest text-center px-4 leading-tight">फाइल चुनें या आधार की फोटो अपलोड करें</span>
                    </div>
                  )}
                </label>
              </div>
            </div>

            <button 
              onClick={runDPIVerification}
              disabled={!selfie || !aadharScan}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold flex items-center justify-center space-x-2 disabled:opacity-30 transition-all shadow-xl shadow-orange-600/10"
            >
              <span>सत्यापन के लिए सबमिट करें</span>
              <ShieldCheck className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in duration-500">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-orange-100 rounded-full"></div>
              <div className="absolute inset-0 w-32 h-32 border-4 border-orange-600 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Fingerprint className="w-12 h-12 text-orange-600 animate-pulse" />
              </div>
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-gray-900">DPI सत्यापन जारी है...</h2>
              <p className="text-gray-500 text-sm font-medium px-4">
                हम आपके आधार विवरण और पहचान का मिलान सरकारी डेटाबेस से कर रहे हैं। इसमें कुछ सेकंड लग सकते हैं।
              </p>
            </div>
            <div className="w-full bg-gray-50 p-4 rounded-2xl border border-gray-100 flex items-center justify-center space-x-3 text-xs font-bold text-orange-800 uppercase tracking-widest">
              <ShieldCheck className="w-4 h-4" />
              <span>सुरक्षित सरकारी गेटवे</span>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-8 inline-flex items-center text-gray-400 font-bold text-sm uppercase tracking-widest hover:text-gray-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            पीछे (Back)
          </button>
        )}
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 10%; }
          100% { top: 90%; }
        }
        .animate-scan {
          position: absolute;
          animation: scan 3s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default Registration;

import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff, RefreshCcw, Circle } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [isListeningAddress, setIsListeningAddress] = useState(false);
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' },
    activeSchemes: [],
    loanStatus: 'none',
    activityHistory: []
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [activeStream, setActiveStream] = useState<MediaStream | null>(null);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  // Hook to connect stream to video element when it mounts
  useEffect(() => {
    if (isCameraActive && activeStream && videoRef.current) {
      videoRef.current.srcObject = activeStream;
    }
  }, [isCameraActive, activeStream]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।');
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      setActiveStream(stream);
      setIsCameraActive(true);
      // Logic for connecting stream is now in useEffect
    } catch (err) {
      setError('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।');
      console.error("Camera error:", err);
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      // Ensure video dimensions are ready
      if (video.videoWidth === 0 || video.videoHeight === 0) {
        setError('कैमरा तैयार हो रहा है, कृपया पुनः प्रयास करें।');
        return;
      }

      const context = canvas.getContext('2d');
      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;

        // Mirror the capture to match the mirrored preview
        context.translate(canvas.width, 0);
        context.scale(-1, 1);
        context.drawImage(video, 0, 0);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setSelfie(dataUrl);

        // Stop the stream
        if (activeStream) {
          activeStream.getTracks().forEach(track => track.stop());
          setActiveStream(null);
        }
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") + "लखनऊ मुख्य बाजार (स्वचालित रूप से निर्धारित)" 
            }
          }));
        },
        () => setError('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से अपना पता दर्ज करें।'),
        { timeout: 10000 }
      );
    }
  };

  const toggleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('आपका ब्राउज़र वॉयस इनपुट का समर्थन नहीं करता है।');
      return;
    }

    if (isListeningAddress) {
      setIsListeningAddress(false);
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'hi-IN';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListeningAddress(true);
      setError(null);
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setProfile(prev => ({
        ...prev,
        location: {
          ...prev.location!,
          address: (prev.location?.address ? prev.location.address + " " : "") + transcript
        }
      }));
      setIsListeningAddress(false);
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      setIsListeningAddress(false);
      if (event.error === 'no-speech') {
        setError('कोई आवाज़ नहीं सुनी गई। कृपया फिर से कोशिश करें।');
      } else {
        setError('वॉयस इनपुट में समस्या आई।');
      }
    };

    recognition.onend = () => {
      setIsListeningAddress(false);
    };

    recognition.start();
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);
    setTimeout(() => {
      if (result.success) {
        const finalProfile = { 
          ...profile, 
          mobile, 
          selfie, 
          aadharScan, 
          isVerified: true,
          activeSchemes: ['PM SVANidhi'],
          loanStatus: 'eligible' as const,
          activityHistory: [{ date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }), action: 'Registration Completed' }]
        };
        onComplete(finalProfile as VendorProfile);
      } else {
        setError(result.message || 'सत्यापन विफल। कृपया पुनः प्रयास करें।');
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 3000);
  };

  return (
    <div className="max-w-xl mx-auto px-4 py-12">
      {/* Voice Assistant */}
      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center space-x-3 text-red-700 animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      <div className="bg-white p-8 md:p-12 rounded-[40px] shadow-2xl shadow-gray-200/50 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-8">
            <div className="space-y-2">
              <h2 className="text-3xl font-bold text-gray-900">आपका स्वागत है</h2>
              <p className="text-gray-500">पंजीकरण शुरू करने के लिए अपना mobile नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700 ml-1">मोबाइल नंबर</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000-00000"
                    maxLength={10}
                    className="w-full pl-14 pr-4 py-5 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 transition-all text-xl tracking-widest font-bold"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold text-lg flex items-center justify-center space-x-2">
                {isVerifying ? <Loader2 className="w-6 h-6 animate-spin" /> : <><span>OTP भेजें</span> <ArrowRight className="w-5 h-5" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-6">
            <h2 className="text-2xl font-bold text-gray-900">विवरण भरें</h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पूर्ण नाम (Full Name)</label>
                <input 
                  type="text"
                  placeholder="आपका नाम दर्ज करें"
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold"
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">आधार नंबर (Aadhar Number)</label>
                <input 
                  type="tel"
                  placeholder="0000 0000 0000"
                  maxLength={12}
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-mono font-bold tracking-[0.2em]"
                  value={profile.aadharNumber}
                  onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">व्यापार की श्रेणी (Category)</label>
                <select 
                  className="w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-orange-600 font-bold appearance-none"
                  value={profile.businessType}
                  onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                >
                  <option value="">श्रेणी चुनें</option>
                  {BUSINESS_TYPES.map(t => <option key={t.id} value={t.label}>{t.label}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-widest ml-1">पता (Address)</label>
                  <div className="flex space-x-3">
                    <button 
                      onClick={toggleVoiceInput} 
                      className={`text-[10px] font-bold uppercase flex items-center transition-all ${isListeningAddress ? 'text-red-600 animate-pulse' : 'text-indigo-600 hover:text-indigo-800'}`}
                    >
                      {isListeningAddress ? <MicOff className="w-3 h-3 mr-1" /> : <Mic className="w-3 h-3 mr-1" />}
                      {isListeningAddress ? 'सुन रहा हूँ...' : 'बोलें (Speak)'}
                    </button>
                    <button onClick={handleLocationDetect} className="text-[10px] font-bold text-orange-600 uppercase flex items-center hover:text-orange-800">
                      <MapPin className="w-3 h-3 mr-1" /> स्थान चुनें
                    </button>
                  </div>
                </div>
                <textarea 
                  className={`w-full p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 transition-all h-24 resize-none font-medium text-sm ${isListeningAddress ? 'ring-2 ring-indigo-500 bg-indigo-50/30 shadow-inner' : 'focus:ring-orange-600'}`}
                  placeholder={isListeningAddress ? "सुन रहा हूँ... कृपया अपना पता बोलें" : "दुकान/व्यवसाय का पता दर्ज करें या ऊपर 'बोलें' बटन दबाएं"}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>

            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError('कृपया सभी आवश्यक जानकारी भरें।');
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold mt-4 flex items-center justify-center space-x-2"
            >
              <span>पहचान सत्यापित करें</span>
              <Fingerprint className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-8">
            <h2 className="text-2xl font-bold text-gray-900 text-center">डिजिटल सत्यापन</h2>

            <div className="space-y-6">
              {/* Selfie Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">1. अपनी सेल्फी लें</p>
                <div className="relative aspect-[4/3] bg-gray-900 rounded-[32px] overflow-hidden group shadow-inner">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-2 hover:bg-gray-800 transition-colors">
                      <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-2">
                        <Camera className="w-8 h-8 text-white" />
                      </div>
                      <span className="font-bold text-xs uppercase tracking-widest text-white/80">कैमरा चालू करें</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full animate-in zoom-in-105 duration-500">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <div className="absolute top-4 left-4 bg-green-500 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center shadow-lg">
                        <CheckCircle2 className="w-3 h-3 mr-1" /> फोटो सुरक्षित है
                      </div>
                      <button 
                        onClick={() => {setSelfie(null); startCamera();}} 
                        className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white text-gray-900 px-6 py-3 rounded-2xl font-bold text-sm flex items-center space-x-2 shadow-2xl hover:bg-gray-50 active:scale-95 transition-all"
                      >
                        <RefreshCcw className="w-4 h-4 text-orange-600" />
                        <span>फिर से लें (Retake)</span>
                      </button>
                    </div>
                  ) : (
                    <>
                      {/* Mirrored Live Feed for Selfie UX */}
                      <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />

                      {/* Live Indicator Overlay */}
                      <div className="absolute top-4 left-4 flex items-center space-x-2 bg-black/40 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
                         <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                         <span className="text-[10px] font-bold text-white uppercase tracking-widest">LIVE FEED</span>
                      </div>

                      {/* Framing Guide */}
                      <div className="absolute inset-0 border-[20px] border-black/40 pointer-events-none flex items-center justify-center">
                         <div className="w-48 h-64 border-2 border-white/50 rounded-full border-dashed animate-pulse duration-[2000ms]"></div>
                      </div>

                      {/* DPI Style Scanning Line Overlay */}
                      <div className="absolute inset-x-0 h-px bg-orange-500/50 shadow-[0_0_15px_rgba(249,115,22,0.5)] animate-scan pointer-events-none"></div>

                      {/* ENHANCED CAPTURE BUTTON WITH MINI PREVIEW */}
                      <button 
                        onClick={captureSelfie} 
                        className="absolute bottom-6 left-1/2 -translate-x-1/2 w-24 h-24 bg-white/20 backdrop-blur-xl rounded-full border-4 border-white/50 flex items-center justify-center shadow-2xl active:scale-90 transition-all group overflow-hidden"
                      >
                        {/* Inner Mini Live Preview */}
                        <div className="absolute inset-1 rounded-full overflow-hidden border-2 border-orange-600">
                           <video 
                              autoPlay 
                              playsInline 
                              muted 
                              className="w-full h-full object-cover scale-x-[-1] opacity-80"
                              ref={(el) => { if(el && activeStream) el.srcObject = activeStream; }}
                           />
                           <div className="absolute inset-0 bg-orange-600/10 group-hover:bg-transparent transition-colors"></div>
                        </div>
                        <Camera className="w-8 h-8 text-white relative z-10 drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)]" />
                      </button>

                      <p className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white/30 text-[40px] font-bold opacity-10 pointer-events-none select-none">UP GOVT</p>
                      <p className="absolute bottom-32 left-1/2 -translate-x-1/2 text-white text-[10px] font-bold uppercase tracking-widest text-center w-full px-4 drop-shadow-md">बटन के अंदर अपना चेहरा देखें और क्लिक करें</p>
                    </>
                  )}
                  <canvas ref={canvasRef} className="hidden" />
                </div>
              </div>

              {/* Aadhar Upload Section */}
              <div className="space-y-3">
                <p className="text-sm font-bold text-gray-500 uppercase tracking-widest text-center">2. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-32 border-2 border-dashed rounded-[32px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-200 bg-gray-50 hover:bg-gray-100'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-2 animate-in fade-in">
                      <div className="flex items-center space-x-2 text-green-700">
                        <CheckCircle2 className="w-6 h-6" />
                        <span className="font-bold">आधार स्कैन प्राप्त हुआ</span>
                      </div>
                      <span className="text-[10px] font-bold text-green-600/60 uppercase tracking-widest underline">बदलने के लिए यहाँ दबाएं</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center text-gray-400 space-y-1">
                      <Upload className="w-6 h-6" />
                      <span className="text-[10px] font-bold uppercase tracking-widest text-center px-4 leading-tight">फाइल चुनें या आधार की फोटो अपलोड करें</span>
                    </div>
                  )}
                </label>
              </div>
            </div>

            <button 
              onClick={runDPIVerification}
              disabled={!selfie || !aadharScan}
              className="w-full py-5 bg-orange-600 text-white rounded-2xl font-bold flex items-center justify-center space-x-2 disabled:opacity-30 transition-all shadow-xl shadow-orange-600/10"
            >
              <span>सत्यापन के लिए सबमिट करें</span>
              <ShieldCheck className="w-5 h-5" />
            </button>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in fade-in duration-500">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-orange-100 rounded-full"></div>
