  name: string;
  mobile: string;
  aadharNumber: string;
  businessType: string;
  location: {
    lat: number;
    lng: number;
    address: string;
  };
  vendingType: 'fixed' | 'mobile' | 'seasonal';
  isVerified: boolean;
  selfie?: string;
  aadharScan?: string;
  activeSchemes?: string[];
  loanStatus?: 'eligible' | 'applied' | 'under_review' | 'approved' | 'none';
  activityHistory?: ActivityLog[];
}

export interface Scheme {
  id: string;
  title: string;
  titleHi: string;
  description: string;
  descriptionHi: string;
  icon: string;
}

import React from 'react';
import { QrCode, MapPin, Calendar, CheckCircle, ShieldCheck, Landmark, Gift, History, Award, TrendingUp, Clock, FileCheck } from 'lucide-react';
import { VendorProfile } from '../types';

interface VendorCardProps {
  profile: VendorProfile;
}

const VendorCard: React.FC<VendorCardProps> = ({ profile }) => {
  // Extract dynamic data from profile
  const activeSchemes = profile.activeSchemes || [];
  const schemeCount = activeSchemes.length;
  const loanStatus = profile.loanStatus || 'none';
  const lastActivity = profile.activityHistory && profile.activityHistory.length > 0 
    ? profile.activityHistory[0].date 
    : new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });

  // Map loan status to display text, icons and styles
  const getLoanStatusDisplay = () => {
    switch (loanStatus) {
      case 'eligible':
        return {
          text: 'मुद्रा ऋण हेतु पात्र (Eligible for Mudra Loan)',
          color: 'text-blue-700',
          bg: 'bg-blue-50',
          border: 'border-blue-100',
          icon: <Landmark className="w-3.5 h-3.5 mr-2 text-blue-600" />,
          progress: 25
        };
      case 'applied':
        return {
          text: 'आवेदन जमा किया गया (Loan Application Submitted)',
          color: 'text-orange-700',
          bg: 'bg-orange-50',
          border: 'border-orange-100',
          icon: <FileCheck className="w-3.5 h-3.5 mr-2 text-orange-600" />,
          progress: 50
        };
      case 'under_review':
        return {
          text: 'सत्यापन जारी (Application Under Review)',
          color: 'text-amber-700',
          bg: 'bg-amber-50',
          border: 'border-amber-100',
          icon: <Clock className="w-3.5 h-3.5 mr-2 text-amber-600" />,
          progress: 75
        };
      case 'approved':
        return {
          text: 'ऋण स्वीकृत (Loan Approved & Disbursed)',
          color: 'text-green-700',
          bg: 'bg-green-50',
          border: 'border-green-100',
          icon: <CheckCircle className="w-3.5 h-3.5 mr-2 text-green-600" />,
          progress: 100
        };
      case 'none':
      default:
        return {
          text: 'जाँच जारी (Evaluation in Progress)',
          color: 'text-gray-600',
          bg: 'bg-gray-50',
          border: 'border-gray-100',
          icon: <Landmark className="w-3.5 h-3.5 mr-2 text-gray-400" />,
          progress: 10
        };
    }
  };

  const loanInfo = getLoanStatusDisplay();

  return (
    <div className="w-full max-w-sm mx-auto bg-white rounded-[40px] shadow-2xl overflow-hidden border border-gray-100 relative group transition-all duration-500 hover:shadow-orange-200/40">

      {/* Top Banner: Official Govt Header */}
      <div className="bg-gradient-to-r from-orange-600 to-orange-500 h-32 p-6 flex justify-between items-start text-white relative overflow-hidden">
        {/* Decorative Seal Pattern */}
        <div className="absolute top-0 right-0 opacity-10 transform translate-x-1/4 -translate-y-1/4">
          <Award className="w-40 h-40 rotate-12" />
        </div>

        <div className="relative z-10">
          <div className="flex items-center space-x-2 mb-1">
            <div className="w-6 h-6 bg-white/20 rounded flex items-center justify-center backdrop-blur-sm border border-white/30">
               <span className="text-[10px] font-bold">UP</span>
            </div>
            <h2 className="text-sm font-bold leading-none tracking-widest uppercase">E-Vendor ID Card</h2>
          </div>
          <p className="text-[9px] opacity-90 uppercase tracking-[0.15em] font-bold">Government of Uttar Pradesh</p>
          <p className="text-[8px] opacity-70 mt-0.5">उत्तर प्रदेश शासन</p>
        </div>

        <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/20 relative z-10">
          <ShieldCheck className="w-7 h-7 text-white" />
        </div>
      </div>

      {/* Profile & Floating Badges */}
      <div className="px-6 -mt-12 relative z-20">
        <div className="flex justify-between items-end">
          <div className="w-28 h-28 bg-gray-50 rounded-[32px] border-4 border-white shadow-2xl flex items-center justify-center text-gray-400 overflow-hidden group-hover:scale-105 transition-transform duration-500">
            {profile.selfie ? (
              <img src={profile.selfie} alt="Vendor" className="w-full h-full object-cover" />
            ) : (
              <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${profile.mobile}`} alt="Vendor" className="w-full h-full object-cover" />
            )}
          </div>
          <div className="pb-2 space-y-2 flex flex-col items-end">
            <div className="bg-green-600 text-white px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-[0.1em] flex items-center shadow-lg shadow-green-200 border border-green-400">
              <CheckCircle className="w-3 h-3 mr-1.5" />
              Verified
            </div>
            {/* Active Schemes Count Badge */}
            <div className="bg-white text-orange-600 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-[0.1em] flex items-center shadow-md border border-orange-100 animate-in fade-in slide-in-from-right-2 duration-700">
              <Gift className="w-3 h-3 mr-1.5" />
              {schemeCount} Active {schemeCount === 1 ? 'Scheme' : 'Schemes'}
            </div>
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="p-7 pt-6 space-y-6">
        <div>
          <div className="flex items-center space-x-2 mb-1">
             <h3 className="text-2xl font-black text-gray-900 tracking-tight leading-none">{profile.name}</h3>
             <TrendingUp className="w-4 h-4 text-green-500 opacity-50" />
          </div>
          <div className="flex items-center text-xs font-bold text-orange-600 uppercase tracking-widest mt-1">
            <span className="bg-orange-50 px-2 py-0.5 rounded border border-orange-100">{profile.businessType}</span>
          </div>
        </div>

        {/* Dynamic Credit & Loan Status Section */}
        <div className={`p-4 rounded-3xl border ${loanInfo.border} ${loanInfo.bg} transition-all duration-500`}>
           <div className="flex items-center text-[9px] text-gray-400 uppercase font-black tracking-widest mb-2">
              {loanInfo.icon} वित्तीय स्थिति (Financial Status)
           </div>
           <p className={`text-[11px] font-bold ${loanInfo.color} leading-snug mb-3`}>
             {loanInfo.text}
           </p>
           <div className="w-full bg-black/5 h-1.5 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ease-out rounded-full ${
                  loanStatus === 'approved' ? 'bg-green-600' : 
                  loanStatus === 'under_review' ? 'bg-amber-500' :
                  loanStatus === 'applied' ? 'bg-orange-500' : 'bg-blue-600'
                }`}
                style={{ width: `${loanInfo.progress}%` }}
              ></div>
           </div>
        </div>

        {/* Metadata Grid */}
        <div className="grid grid-cols-2 gap-4 py-4 border-y border-gray-100">
          <div className="space-y-1">
            <div className="flex items-center text-[9px] text-gray-400 uppercase font-bold tracking-widest">
              <MapPin className="w-3 h-3 mr-1.5 text-gray-300" /> कार्य क्षेत्र
            </div>
            <p className="text-[11px] font-bold text-gray-800 line-clamp-1">
              {profile.location?.address?.split(',')[0] || 'Lucknow, UP'}
            </p>
          </div>
          <div className="space-y-1 border-l border-gray-100 pl-4">
            <div className="flex items-center text-[9px] text-gray-400 uppercase font-bold tracking-widest">
              <History className="w-3 h-3 mr-1.5 text-gray-300" /> सक्रियता
            </div>
            <p className="text-[11px] font-bold text-gray-800">{lastActivity}</p>
          </div>
        </div>

        {/* Card Footer: ID & QR */}
        <div className="flex items-center justify-between pt-2">
          <div className="space-y-1.5">
            <div className="text-[9px] text-gray-400 uppercase font-black tracking-[0.2em] opacity-60">Vendor Registration No.</div>
            <div className="bg-gray-50 px-3 py-2 rounded-xl border border-gray-100">
               <p className="text-sm font-mono font-black text-gray-900 tracking-widest">
                 UP-V-{profile.aadharNumber?.slice(-4) || '7829'}
               </p>
            </div>
          </div>
          <div className="p-2.5 bg-gray-50 rounded-[20px] border border-gray-100 group-hover:bg-white group-hover:border-orange-300 transition-all duration-300 shadow-sm relative">
            <QrCode className="w-12 h-12 text-gray-800 group-hover:text-orange-600 transition-colors" />
            <div className="absolute -top-1 -right-1 w-3 h-3 bg-orange-600 rounded-full border-2 border-white"></div>
          </div>
        </div>
      </div>

      {/* Official Watermark Effect */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden rounded-[40px]">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[150%] h-[150%] bg-[radial-gradient(circle_at_center,rgba(249,115,22,0.03)_0%,transparent_70%)] opacity-50"></div>
        <p className="absolute bottom-4 left-1/2 -translate-x-1/2 text-[40px] font-black text-gray-900/5 rotate-[-15deg] whitespace-nowrap select-none">
          UTTAR PRADESH GOVERNMENT
        </p>
      </div>
    </div>
  );
};

export default VendorCard;

import React, { useState } from 'react';
import { VendorProfile } from '../types';
import { SCHEMES } from '../constants';
import VendorCard from '../components/VendorCard';
import { Download, Share2, CreditCard, Gift, Landmark, ShieldCheck, ArrowRight, Loader2, CheckCircle, TrendingUp } from 'lucide-react';

interface DashboardProps {
  profile: VendorProfile;
}

const Dashboard: React.FC<DashboardProps> = ({ profile }) => {
  const [bankConsent, setBankConsent] = useState(false);
  const [applyingFor, setApplyingFor] = useState<string | null>(null);
  const [appliedSchemes, setAppliedSchemes] = useState<string[]>([]);
  const [checkingOffers, setCheckingOffers] = useState(false);

  // Local state to simulate profile updates for the dynamic VendorCard
  const [localProfile, setLocalProfile] = useState<VendorProfile>(profile);

  const handleApplyScheme = (schemeId: string) => {
    setApplyingFor(schemeId);
    // Simulate API call for scheme application
    setTimeout(() => {
      setAppliedSchemes([...appliedSchemes, schemeId]);

      // Dynamically update the profile status in the card
      setLocalProfile(prev => ({
        ...prev,
        loanStatus: 'applied',
        activityHistory: [
          { date: 'Just Now', action: `Applied for ${schemeId}` },
          ...(prev.activityHistory || [])
        ]
      }));

      setApplyingFor(null);
    }, 2000);
  };

  const handleCheckOffers = () => {
    setCheckingOffers(true);
    setTimeout(() => {
      setCheckingOffers(false);
      // Change status to under_review after checking offers to show progress
      setLocalProfile(prev => ({
        ...prev,
        loanStatus: 'under_review',
        activityHistory: [
          { date: 'Just Now', action: 'Credit Review Started' },
          ...(prev.activityHistory || [])
        ]
      }));
      alert('बधाई हो! आप मुद्रा ऋण के लिए ₹50,000 तक के लिए पात्र हैं। आपका बैंक सत्यापन शुरू कर चुका है।');
    }, 3000);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-16 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">

        {/* Left Column: ID Card & Quick Actions */}
        <div className="lg:col-span-4 space-y-10">
          <div className="sticky top-24 space-y-10">
            <div className="flex items-center justify-between px-2">
              <h2 className="text-2xl font-black text-gray-900 tracking-tight">आपका डिजिटल कार्ड</h2>
              <div className="flex items-center space-x-2 bg-orange-50 px-3 py-1 rounded-full border border-orange-100">
                 <div className="w-2 h-2 bg-orange-600 rounded-full animate-pulse"></div>
                 <span className="text-[10px] font-black text-orange-600 uppercase tracking-widest">Live Sync</span>
              </div>
            </div>

            <VendorCard profile={localProfile} />

            <div className="grid grid-cols-2 gap-5">
              <button 
                onClick={() => alert('कार्ड डाउनलोड हो रहा है...')}
                className="flex flex-col items-center justify-center p-8 bg-white rounded-[40px] border border-gray-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group"
              >
                <div className="w-14 h-14 bg-orange-50 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 group-hover:bg-orange-600 transition-all duration-500">
                  <Download className="w-7 h-7 text-orange-600 group-hover:text-white" />
                </div>
                <span className="text-[10px] font-black text-gray-700 uppercase tracking-widest">Download ID</span>
              </button>
              <button 
                onClick={() => alert('शेयरिंग लिंक कॉपी हो गया है।')}
                className="flex flex-col items-center justify-center p-8 bg-white rounded-[40px] border border-gray-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all group"
              >
                <div className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 group-hover:bg-blue-600 transition-all duration-500">
                  <Share2 className="w-7 h-7 text-blue-600 group-hover:text-white" />
                </div>
                <span className="text-[10px] font-black text-gray-700 uppercase tracking-widest">Share Card</span>
              </button>
            </div>

            <div className="bg-gradient-to-br from-green-50 to-white p-8 rounded-[40px] border border-green-100 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 p-4 opacity-5">
                 <ShieldCheck className="w-20 h-20" />
               </div>
               <div className="flex items-center space-x-3 mb-4">
                 <ShieldCheck className="w-6 h-6 text-green-600" />
                 <h3 className="font-black text-green-900 uppercase text-xs tracking-widest">Official Verification</h3>
               </div>
               <p className="text-xs text-green-800 opacity-80 leading-relaxed font-medium hindi">
                 यह कार्ड मुख्यमंत्री जी के निर्देशानुसार उत्तर प्रदेश शासन द्वारा मान्य है। इसे व्यापारिक पहचान के रूप में पुलिस या प्रशासनिक जाँच के दौरान गर्व से दिखाएं।
               </p>
            </div>
          </div>
        </div>

        {/* Right Column: Schemes & Banking */}
        <div className="lg:col-span-8 space-y-16">

          {/* Greeting */}
          <div className="relative">
            <div className="absolute -left-12 top-1/2 -translate-y-1/2 w-1 h-12 bg-orange-500 rounded-full hidden md:block"></div>
            <h1 className="text-5xl font-black text-gray-900 mb-4 tracking-tighter">नमस्ते, {profile.name}!</h1>
            <p className="text-xl text-gray-500 font-medium max-w-2xl leading-relaxed">
              मुख्यमंत्री व्यापारी सशक्तिकरण योजना के डैशबोर्ड में आपका स्वागत है। आपके व्यापार की उन्नति के लिए सभी सरकारी सुविधाएं यहाँ उपलब्ध हैं।
            </p>
          </div>

          {/* Scheme Discovery */}
          <section className="space-y-8">
            <div className="flex items-center justify-between px-2">
              <h2 className="text-2xl font-black text-gray-900 flex items-center tracking-tight">
                <Gift className="w-8 h-8 mr-4 text-orange-500" />
                आपके लिए विशेष योजनाएं
              </h2>
              <button className="text-[10px] font-black text-orange-600 hover:text-orange-700 uppercase tracking-[0.2em] border-b-2 border-orange-200 pb-1">View All Benefits</button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {SCHEMES.map((scheme) => (
                <div key={scheme.id} className="p-10 bg-white rounded-[56px] border border-gray-100 shadow-[0_20px_40px_-12px_rgba(0,0,0,0.05)] hover:shadow-2xl hover:shadow-orange-200/20 hover:-translate-y-2 transition-all duration-500 flex flex-col group relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-orange-500/[0.03] rounded-full -mr-16 -mt-16 group-hover:scale-150 transition-transform duration-700"></div>

                  <div className="mb-8 flex justify-between items-start">
                    <div className="w-16 h-16 bg-gray-50 rounded-3xl flex items-center justify-center group-hover:bg-orange-600 group-hover:text-white transition-all duration-500 shadow-sm">
                      <TrendingUp className="w-7 h-7" />
                    </div>
                    <div className="bg-green-50 text-green-700 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border border-green-100">Eligible</div>
                  </div>
                  <h3 className="text-2xl font-black text-gray-900 mb-3 hindi leading-tight">{scheme.titleHi}</h3>
                  <p className="text-gray-500 mb-10 leading-relaxed font-medium flex-grow italic">"{scheme.descriptionHi}"</p>

                  {appliedSchemes.includes(scheme.id) ? (
                    <div className="w-full py-5 bg-green-50 text-green-700 rounded-[28px] font-black text-sm uppercase tracking-widest flex items-center justify-center space-x-3 border-2 border-green-200 animate-in zoom-in-95">
                      <CheckCircle className="w-5 h-5" />
                      <span>Application Successful</span>
                    </div>
                  ) : (
                    <button 
                      onClick={() => handleApplyScheme(scheme.id)}
                      disabled={!!applyingFor}
                      className="w-full py-5 bg-gray-900 text-white rounded-[28px] font-black text-sm uppercase tracking-widest hover:bg-orange-600 transition-all duration-300 flex items-center justify-center space-x-3 disabled:opacity-50 active:scale-95 shadow-xl shadow-gray-900/10"
                    >
                      {applyingFor === scheme.id ? <Loader2 className="w-5 h-5 animate-spin" /> : <><span>Apply Now</span> <ArrowRight className="w-5 h-5" /></>}
                    </button>
                  )}
                </div>
              ))}
            </div>
          </section>

          {/* Banking & Credit Enablement */}
          <section className="p-12 bg-gradient-to-br from-indigo-950 via-blue-900 to-indigo-900 rounded-[64px] text-white overflow-hidden relative shadow-[0_40px_80px_-12px_rgba(30,58,138,0.3)] border-4 border-white/5">
            <div className="relative z-10 space-y-10">
              <div className="flex items-center space-x-6">
                <div className="w-20 h-20 bg-white/10 rounded-[32px] flex items-center justify-center backdrop-blur-2xl border border-white/20 shadow-2xl">
                   <Landmark className="w-10 h-10 text-blue-300" />
                </div>
                <div>
                  <h2 className="text-3xl font-black tracking-tight mb-1">वित्तीय समावेशन एवं ऋण सुविधा</h2>
                  <p className="text-blue-200 text-lg font-medium opacity-80">बिना गारंटी के मुद्रा और स्वनिधि ऋण हेतु बैंक गेटवे</p>
                </div>
              </div>

              <div className="space-y-6">
                <div 
                  className="flex items-start space-x-6 bg-white/5 p-8 rounded-[40px] border border-white/10 group cursor-pointer hover:bg-white/[0.08] transition-all" 
