                   <label className="text-base text-blue-50 leading-relaxed font-medium cursor-pointer hindi">
                     मैं अपनी व्यापारिक जानकारी और आधार डेटा को सरकारी प्रमाणित बैंकों के साथ साझा करने की सहमति देता हूँ ताकि वे मुझे उपयुक्त ऋण (Loan) के प्रस्ताव भेज सकें।
                   </label>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  <div className="p-6 bg-white/5 rounded-3xl border border-white/5 flex items-center space-x-4 backdrop-blur-sm">
                    <div className="w-10 h-10 bg-blue-500/20 rounded-2xl flex items-center justify-center">
                      <CreditCard className="w-5 h-5 text-blue-300" />
                    </div>
                    <span className="text-xs font-black text-blue-100 uppercase tracking-[0.2em]">Mudra Loan Ready</span>
                  </div>
                  <div className="p-6 bg-white/5 rounded-3xl border border-white/5 flex items-center space-x-4 backdrop-blur-sm">
                    <div className="w-10 h-10 bg-green-500/20 rounded-2xl flex items-center justify-center">
                      <ShieldCheck className="w-5 h-5 text-green-300" />
                    </div>
                    <span className="text-xs font-black text-blue-100 uppercase tracking-[0.2em]">No Collateral</span>
                  </div>
                </div>

                <button 
                  onClick={handleCheckOffers}
                  disabled={!bankConsent || checkingOffers}
