import React, { useState, useRef, useEffect } from 'react';
import { 
  QrCode, 
  CheckCircle, 
  ShieldCheck, 
  Landmark, 
  Gift, 
  History, 
  Award, 
  Clock, 
  FileCheck, 
  Shield, 
  Zap,
  Star,
  Sparkles,
  X,
  Fingerprint,
  ExternalLink,
  ChevronDown,
  Activity,
  CreditCard,
  Verified,
  BadgeCheck,
  MousePointer2,
  Scan,
  Camera,
  Loader2,
  ShieldAlert,
  MapPin,
  TrendingUp,
  Target
} from 'lucide-react';
import { VendorProfile } from '../types';

interface VendorCardProps {
  profile: VendorProfile;
}

const VendorCard: React.FC<VendorCardProps> = ({ profile }) => {
  const [isQrExpanded, setIsQrExpanded] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isVerifyingScan, setIsVerifyingScan] = useState(false);
  const [scanResult, setScanResult] = useState<'success' | 'error' | null>(null);
  const [animateProgress, setAnimateProgress] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => setAnimateProgress(true), 500);
    return () => clearTimeout(timer);
  }, [profile.loanStatus]);

  const toggleQrModal = () => setIsQrExpanded(!isQrExpanded);

  const activeSchemes = profile.activeSchemes || [];
  const schemeCount = activeSchemes.length;
  const loanStatus = profile.loanStatus || 'none';
  const history = profile.activityHistory || [];
  const lastActivity = history.length > 0 
    ? history[0].date 
    : new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });

  const startScanner = async () => {
    setIsScannerOpen(true);
    setScanResult(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied:", err);
      alert("कैमरा एक्सेस करने में असमर्थ। कृपया अनुमति दें।");
      setIsScannerOpen(false);
    }
  };

  const closeScanner = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
    }
    setIsScannerOpen(false);
    setIsVerifyingScan(false);
    setScanResult(null);
  };

  const simulateScan = () => {
    setIsVerifyingScan(true);
    setTimeout(() => {
      setIsVerifyingScan(false);
      setScanResult('success');
    }, 2000);
  };

  const getLoanStatusDisplay = () => {
    switch (loanStatus) {
      case 'eligible':
        return {
          text: 'ऋण हेतु पात्र (Eligible)',
          subText: 'Pre-Approved Micro-Credit',
          color: 'text-blue-700',
          bg: 'bg-blue-50/40',
          border: 'border-blue-100',
          indicator: 'bg-blue-500',
          progress: 30,
          grade: 'Grade A+'
        };
      case 'applied':
        return {
          text: 'आवेदन जमा (Applied)',
          subText: 'Under Bank Verification',
          color: 'text-orange-700',
          bg: 'bg-orange-50/40',
          border: 'border-orange-100',
          indicator: 'bg-orange-500',
          progress: 60,
          grade: 'Processing'
        };
      case 'under_review':
        return {
          text: 'सत्यापन जारी (Review)',
          subText: 'Final DPI Validation',
          color: 'text-amber-700',
          bg: 'bg-amber-50/40',
          border: 'border-amber-100',
          indicator: 'bg-amber-500',
          progress: 85,
          grade: 'High Trust'
        };
      case 'approved':
        return {
          text: 'ऋण स्वीकृत (Approved)',
          subText: 'Funds Disbursed',
          color: 'text-green-700',
          bg: 'bg-green-50/40',
          border: 'border-green-100',
          indicator: 'bg-green-600',
          progress: 100,
          grade: 'Verified'
        };
      default:
        return {
          text: 'पात्रता की जाँच (Evaluation)',
          subText: 'System Analysis active',
          color: 'text-gray-600',
          bg: 'bg-gray-50/40',
          border: 'border-gray-100',
          indicator: 'bg-gray-400',
          progress: 15,
          grade: 'N/A'
        };
    }
  };

  const loanInfo = getLoanStatusDisplay();

  const getSchemeStyle = (schemeName: string) => {
    const s = schemeName.toLowerCase();
    if (s.includes('svanidhi')) return { icon: <Landmark className="w-3 h-3" />, label: 'SVANidhi', color: 'text-blue-700', bg: 'bg-blue-50', border: 'border-blue-100' };
    if (s.includes('insurance') || s.includes('bima')) return { icon: <ShieldCheck className="w-3 h-3" />, label: 'Bima', color: 'text-green-700', bg: 'bg-green-50', border: 'border-green-100' };
    if (s.includes('yuva')) return { icon: <Zap className="w-3 h-3" />, label: 'YUVA', color: 'text-amber-700', bg: 'bg-amber-50', border: 'border-amber-200' };
    if (s.includes('vishwakarma')) return { icon: <Star className="w-3 h-3" />, label: 'Shram', color: 'text-purple-700', bg: 'bg-purple-50', border: 'border-purple-100' };
    return { icon: <Gift className="w-3 h-3" />, label: 'Benefit', color: 'text-orange-700', bg: 'bg-orange-50', border: 'border-orange-100' };
  };

  return (
    <>
      <div className="w-full max-w-sm mx-auto bg-white rounded-[56px] shadow-[0_48px_100px_-15px_rgba(249,115,22,0.18)] overflow-hidden border border-gray-100 relative group/card transition-all duration-1000 hover:shadow-[0_60px_120px_-20px_rgba(249,115,22,0.25)] hover:-translate-y-2">

        {/* PREMIUM HOLOGRAPHIC HEADER */}
        <div className="bg-gradient-to-br from-[#E65100] via-[#F57C00] to-[#FF9800] h-44 p-10 flex justify-between items-start text-white relative">
          <div className="absolute top-0 right-0 opacity-[0.08] transform translate-x-1/4 -translate-y-1/4 pointer-events-none group-hover/card:rotate-[45deg] transition-transform duration-[4000ms]">
