  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [isListeningAddress, setIsListeningAddress] = useState(false);
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' },
    activeSchemes: [],
    loanStatus: 'none',
    activityHistory: []
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [activeStream, setActiveStream] = useState<MediaStream | null>(null);

  // Official Scanner States
  const [isOfficialScannerOpen, setIsOfficialScannerOpen] = useState(false);
  const [isVerifyingScan, setIsVerifyingScan] = useState(false);
  const [scanResult, setScanResult] = useState<'success' | 'error' | null>(null);
  const scannerVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step]);

  useEffect(() => {
    if (isCameraActive && activeStream && videoRef.current) {
      videoRef.current.srcObject = activeStream;
    }
  }, [isCameraActive, activeStream]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।');
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      setActiveStream(stream);
      setIsCameraActive(true);
    } catch (err) {
      setError('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।');
      console.error("Camera error:", err);
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      if (video.videoWidth === 0 || video.videoHeight === 0) {
        setError('कैमरा तैयार हो रहा है, कृपया पुनः प्रयास करें।');
        return;
      }

      const context = canvas.getContext('2d');
      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.translate(canvas.width, 0);
        context.scale(-1, 1);
        context.drawImage(video, 0, 0);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setSelfie(dataUrl);

        if (activeStream) {
          activeStream.getTracks().forEach(track => track.stop());
          setActiveStream(null);
        }
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") + "लखनऊ मुख्य बाजार (स्वचालित रूप से निर्धारित)" 
            }
          }));
        },
        () => setError('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से अपना पता दर्ज करें।'),
        { timeout: 10000 }
      );
    }
  };

  const toggleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError('आपका ब्राउज़र वॉयस इनपुट का समर्थन नहीं करता है।');
      return;
    }

    if (isListeningAddress) {
      setIsListeningAddress(false);
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'hi-IN';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListeningAddress(true);
      setError(null);
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setProfile(prev => ({
        ...prev,
        location: {
          ...prev.location!,
          address: (prev.location?.address ? prev.location.address + " " : "") + transcript
        }
      }));
      setIsListeningAddress(false);
    };

    recognition.onerror = (event: any) => {
      console.error('Speech recognition error:', event.error);
      setIsListeningAddress(false);
      if (event.error === 'no-speech') {
        setError('कोई आवाज़ नहीं सुनी गई। कृपया फिर से कोशिश करें।');
      } else {
        setError('वॉयस इनपुट में समस्या आई।');
      }
    };

    recognition.onend = () => {
      setIsListeningAddress(false);
    };

    recognition.start();
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);
    setTimeout(() => {
      if (result.success) {
        const finalProfile = { 
          ...profile, 
          mobile, 
          selfie, 
          aadharScan, 
          isVerified: true,
          activeSchemes: ['PM SVANidhi'],
          loanStatus: 'eligible' as const,
          activityHistory: [{ date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }), action: 'Registration Completed' }]
        };
        onComplete(finalProfile as VendorProfile);
      } else {
        setError(result.message || 'सत्यापन विफल। कृपया पुनः प्रयास करें।');
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 3000);
  };

  // Official Scanner Methods
  const openOfficialScanner = async () => {
    setIsOfficialScannerOpen(true);
    setScanResult(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (scannerVideoRef.current) {
        scannerVideoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied:", err);
      alert("कैमरा एक्सेस करने में असमर्थ। कृपया अनुमति दें।");
      setIsOfficialScannerOpen(false);
    }
  };

  const closeOfficialScanner = () => {
    if (scannerVideoRef.current && scannerVideoRef.current.srcObject) {
      const stream = scannerVideoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
    }
    setIsOfficialScannerOpen(false);
    setIsVerifyingScan(false);
    setScanResult(null);
  };

  const simulateOfficialScan = () => {
    setIsVerifyingScan(true);
    setTimeout(() => {
      setIsVerifyingScan(false);
      setScanResult('success');
    }, 2000);
  };

  const steps = [
    { id: RegistrationStep.AUTH, label: 'मोबाइल नंबर', sub: 'Mobile', icon: <Phone className="w-4 h-4" /> },
    { id: RegistrationStep.PROFILE, label: 'दुकान का विवरण', sub: 'Business', icon: <ClipboardList className="w-4 h-4" /> },
    { id: RegistrationStep.VERIFY_IDENTITY, label: 'सत्यापन', sub: 'Identity', icon: <ScanLine className="w-4 h-4" /> },
    { id: RegistrationStep.PROCESSING, label: 'अंतिम प्रक्रिया', sub: 'Finalizing', icon: <Settings2 className="w-4 h-4" /> },
  ];

  const currentStepIndex = steps.findIndex(s => s.id === step);
  const progressPercentage = ((currentStepIndex + 1) / steps.length) * 100;

  return (
    <div className="max-w-xl mx-auto px-4 py-8 md:py-12 animate-in fade-in duration-700">

      {/* Live Progress Indicator */}
      <div className="mb-10 space-y-6">
        <div className="flex justify-between items-end px-2">
          <div className="space-y-1">
            <h4 className="text-xl font-black text-gray-900 tracking-tight">पंजीकरण प्रगति</h4>
            <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest flex items-center">
              <span className="flex h-1.5 w-1.5 rounded-full bg-orange-600 mr-2 animate-pulse"></span>
              Step {currentStepIndex + 1} of {steps.length}
            </p>
          </div>
          <div className="text-right">
            <p className="text-2xl font-black text-gray-900 leading-none">{Math.round(progressPercentage)}%</p>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">Completion</p>
          </div>
        </div>

        <div className="relative pt-4 pb-2">
          <div className="absolute top-1/2 -translate-y-1/2 left-0 w-full h-1.5 bg-gray-100 rounded-full"></div>
          <div 
            className="absolute top-1/2 -translate-y-1/2 left-0 h-1.5 bg-orange-600 rounded-full transition-all duration-1000 ease-out shadow-[0_0_12px_rgba(249,115,22,0.3)]"
            style={{ width: `${progressPercentage}%` }}
          ></div>

          <div className="relative flex justify-between">
            {steps.map((s, idx) => {
              const isCompleted = currentStepIndex > idx;
              const isActive = currentStepIndex === idx;

              return (
                <div key={s.id} className="flex flex-col items-center">
                  <div 
                    className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all duration-500 border-4 ${
                      isCompleted 
                        ? 'bg-green-600 border-white text-white shadow-lg shadow-green-200' 
                        : isActive 
                        ? 'bg-white border-orange-600 text-orange-600 shadow-xl shadow-orange-100 scale-110' 
                        : 'bg-white border-gray-100 text-gray-300'
                    }`}
                  >
                    {isCompleted ? <CheckCircle2 className="w-5 h-5" /> : s.icon}
                  </div>
                  <div className={`mt-3 text-center transition-all duration-500 ${isActive ? 'opacity-100 translate-y-0' : 'opacity-40 translate-y-1'}`}>
                    <p className={`text-[10px] font-black hindi leading-none ${isActive ? 'text-gray-900' : 'text-gray-500'}`}>{s.label}</p>
                    <p className="text-[8px] font-bold uppercase tracking-[0.1em] text-gray-400 mt-1">{s.sub}</p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Voice Assistant */}
      <div className="mb-8 flex items-center space-x-4 bg-orange-50 p-6 rounded-[32px] border border-orange-100 shadow-sm transition-all duration-500">
        <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md relative group">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping group-hover:pause"></div>
          <Mic className="w-6 h-6 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-xs text-orange-800 uppercase font-bold tracking-widest mb-1 opacity-60">सहायक निर्देश (AI Guidance)</p>
          <p className="text-sm md:text-base font-medium text-orange-900 leading-relaxed italic">
            "{voiceHint || 'लोड हो रहा है...'}"
          </p>
        </div>
      </div>

      {error && (
        <div className="mb-6 p-5 bg-red-50 border border-red-100 rounded-[24px] flex items-center space-x-4 text-red-700 animate-in fade-in slide-in-from-top-2">
          <div className="p-2 bg-red-100 rounded-xl">
            <AlertCircle className="w-5 h-5 shrink-0" />
          </div>
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      <div className="bg-white p-8 md:p-14 rounded-[48px] shadow-2xl shadow-gray-200/40 border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500 relative">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-10">
            <div className="space-y-3">
              <h2 className="text-4xl font-black text-gray-900 tracking-tight">आपका स्वागत है</h2>
              <p className="text-gray-500 font-medium text-lg">पंजीकरण शुरू करने के लिए अपना मोबाइल नंबर दर्ज करें।</p>
            </div>
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">मोबाइल नंबर (Mobile Number)</label>
                <div className="relative group">
                  <span className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400 font-black text-xl">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000-00000"
                    maxLength={10}
                    className="w-full pl-18 pr-6 py-6 bg-gray-50 border-2 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 focus:ring-4 focus:ring-orange-500/10 transition-all text-2xl tracking-[0.2em] font-black"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                  <div className="absolute inset-y-0 right-6 flex items-center pointer-events-none opacity-0 group-focus-within:opacity-100 transition-opacity">
                     <div className="w-2 h-2 bg-orange-500 rounded-full animate-pulse"></div>
                  </div>
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-6 bg-orange-600 text-white rounded-[24px] font-black text-xl flex items-center justify-center space-x-3 shadow-2xl shadow-orange-600/30 hover:bg-orange-700 hover:scale-[1.02] transition-all active:scale-95 disabled:opacity-50">
                {isVerifying ? <Loader2 className="w-7 h-7 animate-spin" /> : <><span>OTP प्राप्त करें</span> <ArrowRight className="w-6 h-6" /></>}
              </button>
            </div>
            <div className="pt-4 flex items-center justify-center space-x-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
              <ShieldCheck className="w-4 h-4" />
              <span>डाटा गोपनीयता उत्तर प्रदेश सरकार द्वारा सुरक्षित</span>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-8">
            <div className="flex justify-between items-start">
               <h2 className="text-3xl font-black text-gray-900 tracking-tight">विवरण भरें</h2>
               <div className="p-3 bg-orange-50 rounded-2xl">
                 <ClipboardList className="w-6 h-6 text-orange-600" />
               </div>
            </div>

            <div className="space-y-5">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">पूर्ण नाम (Full Name)</label>
                <input 
                  type="text"
                  placeholder="आपका नाम दर्ज करें"
                  className="w-full p-5 bg-gray-50 border-2 border-transparent rounded-[20px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg"
                  value={profile.name}
                  onChange={(e) => setProfile({...profile, name: e.target.value})}
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">आधार नंबर (Aadhar Number)</label>
                <input 
                  type="tel"
                  placeholder="0000 0000 0000"
                  maxLength={12}
                  className="w-full p-5 bg-gray-50 border-2 border-transparent rounded-[20px] focus:bg-white focus:border-orange-500 transition-all font-black text-xl tracking-[0.2em]"
                  value={profile.aadharNumber}
                  onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">व्यापार की श्रेणी (Category)</label>
                <div className="relative">
                  <select 
                    className="w-full p-5 bg-gray-50 border-2 border-transparent rounded-[20px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg appearance-none"
                    value={profile.businessType}
                    onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                  >
                    <option value="">श्रेणी चुनें (Select Category)</option>
                    {BUSINESS_TYPES.map(t => <option key={t.id} value={t.label}>{t.label}</option>)}
                  </select>
                  <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none">
                     <ArrowRight className="w-5 h-5 text-gray-400 rotate-90" />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center mb-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">व्यापार का पता (Address)</label>
                  <div className="flex space-x-3">
                    <button 
                      onClick={toggleVoiceInput} 
                      className={`text-[9px] font-black uppercase flex items-center px-2 py-1 rounded-lg transition-all ${isListeningAddress ? 'bg-red-50 text-red-600 animate-pulse' : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'}`}
                    >
                      {isListeningAddress ? <MicOff className="w-3 h-3 mr-1" /> : <Mic className="w-3 h-3 mr-1" />}
                      {isListeningAddress ? 'सुन रहा हूँ...' : 'बोलें (Speak)'}
                    </button>
                    <button onClick={handleLocationDetect} className="text-[9px] font-black bg-orange-50 text-orange-600 uppercase flex items-center px-2 py-1 rounded-lg hover:bg-orange-100 transition-colors">
                      <MapPin className="w-3 h-3 mr-1" /> स्थान चुनें
                    </button>
                  </div>
                </div>
                <textarea 
                  className={`w-full p-5 bg-gray-50 border-2 transition-all h-32 rounded-[20px] resize-none font-bold text-base ${isListeningAddress ? 'border-indigo-500 bg-indigo-50/30 shadow-inner ring-4 ring-indigo-500/10' : 'border-transparent focus:bg-white focus:border-orange-500'}`}
                  placeholder={isListeningAddress ? "सुन रहा हूँ... कृपया अपना पता बोलें" : "दुकान या व्यवसाय का पूरा पता दर्ज करें या ऊपर 'बोलें' बटन का उपयोग करें"}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>

            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError('कृपया सभी आवश्यक जानकारी भरें।');
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-6 bg-orange-600 text-white rounded-[24px] font-black text-xl mt-6 flex items-center justify-center space-x-3 shadow-xl hover:bg-orange-700 transition-all active:scale-95 shadow-orange-600/20"
            >
              <span>पहचान सत्यापित करें</span>
              <Fingerprint className="w-6 h-6" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-10">
             <div className="flex justify-between items-start">
               <h2 className="text-3xl font-black text-gray-900 tracking-tight">डिजिटल सत्यापन</h2>
               <div className="p-3 bg-blue-50 rounded-2xl">
                 <ShieldCheck className="w-6 h-6 text-blue-600" />
               </div>
            </div>

            <div className="space-y-8">
              {/* Selfie Section */}
              <div className="space-y-4">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">१. अपनी सेल्फी लें (Live Photo)</p>
                <div className="relative aspect-[4/3] bg-gray-900 rounded-[40px] overflow-hidden group shadow-[0_20px_40px_-12px_rgba(0,0,0,0.3)] border-4 border-white">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-3 hover:bg-gray-800 transition-colors">
                      <div className="w-20 h-20 bg-white/10 rounded-[32px] flex items-center justify-center mb-2 backdrop-blur-md border border-white/20">
                        <Camera className="w-10 h-10 text-white" />
                      </div>
                      <span className="font-black text-xs uppercase tracking-[0.2em] text-white/80">कैमरा चालू करें</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full animate-in zoom-in-105 duration-700">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <div className="absolute top-6 left-6 bg-green-500 text-white px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center shadow-2xl border border-green-400">
                        <CheckCircle2 className="w-4 h-4 mr-2" /> फोटो प्राप्त हुई
                      </div>
                      <button 
                        onClick={() => {setSelfie(null); startCamera();}} 
                        className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-white/20 backdrop-blur-xl text-white border border-white/30 px-8 py-4 rounded-[24px] font-black text-sm flex items-center space-x-3 shadow-2xl hover:bg-white/30 active:scale-95 transition-all"
                      >
                        <RefreshCcw className="w-5 h-5 text-orange-500" />
                        <span>पुनः प्रयास करें</span>
                      </button>
                    </div>
                  ) : (
                    <>
                      <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
                      <div className="absolute top-6 left-6 flex items-center space-x-2 bg-black/40 backdrop-blur-md px-4 py-2 rounded-full border border-white/10">
                         <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
                         <span className="text-[10px] font-black text-white uppercase tracking-widest">LIVE DATA FEED</span>
                      </div>
                      <div className="absolute inset-0 border-[30px] border-black/40 pointer-events-none flex items-center justify-center">
                         <div className="w-56 h-72 border-2 border-white/30 rounded-full border-dashed animate-pulse duration-[3000ms]"></div>
                      </div>
                      <div className="absolute inset-x-0 h-px bg-orange-500/30 shadow-[0_0_20px_rgba(249,115,22,0.6)] animate-scan pointer-events-none"></div>
                      <button 
                        onClick={captureSelfie} 
                        className="absolute bottom-8 left-1/2 -translate-x-1/2 w-24 h-24 bg-white/10 backdrop-blur-2xl rounded-full border-4 border-white/40 flex items-center justify-center shadow-2xl active:scale-90 transition-all group overflow-hidden"
                      >
                        <div className="absolute inset-1 rounded-full overflow-hidden border-2 border-orange-600">
                           <video 
                              autoPlay 
                              playsInline 
                              muted 
                              className="w-full h-full object-cover scale-x-[-1] opacity-70"
                              ref={(el) => { if(el && activeStream) el.srcObject = activeStream; }}
                           />
                        </div>
                        <Camera className="w-8 h-8 text-white relative z-10" />
                      </button>
                    </>
                  )}
                  <canvas ref={canvasRef} className="hidden" />
                </div>
              </div>

              {/* Aadhar Upload Section */}
              <div className="space-y-4">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">२. आधार कार्ड अपलोड करें</p>
                <label className={`relative h-40 border-2 border-dashed rounded-[40px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50/50' : 'border-gray-200 bg-gray-50/50 hover:bg-white hover:border-orange-300'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-3 animate-in fade-in">
                      <div className="w-12 h-12 bg-green-100 rounded-2xl flex items-center justify-center text-green-600">
                        <CheckCircle2 className="w-7 h-7" />
                      </div>
                      <span className="font-black text-green-900 hindi">दस्तावेज अपलोड सफल</span>
                      <span className="text-[9px] font-black text-green-600/60 uppercase tracking-widest underline">बदलने के लिए क्लिक करें</span>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center text-gray-400 space-y-3">
                      <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-sm">
                        <Upload className="w-6 h-6" />
                      </div>
                      <span className="text-[10px] font-black uppercase tracking-[0.2em] text-center px-8 leading-relaxed">फाइल चुनें या आधार कार्ड की फोटो अपलोड करें</span>
                    </div>
                  )}
                </label>
              </div>
            </div>

            {/* Official Verification Button */}
            <div className="bg-green-50/50 p-6 rounded-[32px] border border-green-100 border-dashed">
              <div className="flex items-center space-x-3 mb-4">
                 <ShieldCheck className="w-5 h-5 text-green-600" />
                 <span className="text-[10px] font-black text-green-800 uppercase tracking-widest">Administrative Link</span>
              </div>
              <button 
                onClick={openOfficialScanner}
                className="w-full py-4 bg-white border-2 border-green-600 text-green-600 rounded-[20px] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center space-x-3 hover:bg-green-600 hover:text-white transition-all shadow-lg shadow-green-100 active:scale-95"
              >
                <Scan className="w-4 h-4" />
                <span>Official Verification</span>
              </button>
            </div>

            <button 
              onClick={runDPIVerification}
              disabled={!selfie || !aadharScan}
              className="w-full py-6 bg-orange-600 text-white rounded-[24px] font-black text-xl flex items-center justify-center space-x-3 disabled:opacity-30 transition-all shadow-2xl shadow-orange-600/20 active:scale-95"
            >
              <span>सत्यापन के लिए सबमिट करें</span>
              <ShieldCheck className="w-6 h-6" />
            </button>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-12 animate-in fade-in duration-700">
            <div className="relative">
              <div className="w-40 h-40 border-8 border-orange-50 rounded-[48px] animate-pulse"></div>
              <div className="absolute inset-0 w-40 h-40 border-8 border-orange-600 border-t-transparent rounded-[48px] animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <Fingerprint className="w-16 h-16 text-orange-600 animate-pulse" />
              </div>
              <div className="absolute -bottom-4 left-1/2 -translate-x-1/2 bg-white px-4 py-1 rounded-full shadow-lg border border-orange-50">
                 <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest">Verifying DPI</p>
              </div>
            </div>
            <div className="space-y-4">
              <h2 className="text-3xl font-black text-gray-900 tracking-tight">सत्यापन जारी है...</h2>
              <p className="text-gray-500 font-medium max-w-sm mx-auto leading-relaxed">
                हम आपके आधार और सेल्फी का मिलान उत्तर प्रदेश सरकार के सुरक्षित डेटाबेस से कर रहे हैं।
              </p>
            </div>
            <div className="w-full bg-blue-50/50 p-6 rounded-[32px] border border-blue-100 flex items-center justify-center space-x-4 text-[10px] font-black text-blue-800 uppercase tracking-[0.3em]">
              <ShieldCheck className="w-6 h-6 text-blue-600" />
              <span>सत्यापित सरकारी गेटवे</span>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-10 inline-flex items-center text-gray-400 font-black text-[10px] uppercase tracking-[0.3em] hover:text-orange-600 transition-all group"
          >
            <ArrowLeft className="w-4 h-4 mr-2 group-hover:-translate-x-1 transition-transform" />
            पीछे (Back)
          </button>
        )}
      </div>

      {/* Official Scanner Modal */}
      {isOfficialScannerOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-gray-950/95 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className="relative w-full max-w-2xl bg-white rounded-[72px] shadow-2xl overflow-hidden border border-white/20 animate-in zoom-in-95 duration-700 flex flex-col max-h-[95vh]">
            <div className="bg-[#181818] p-10 flex justify-between items-center text-white shrink-0">
               <div className="flex items-center space-x-5">
                 <div className="w-14 h-14 bg-green-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-green-600/30 border border-green-500/50">
                    <ShieldCheck className="w-8 h-8" />
                 </div>
                 <div>
                   <h3 className="text-2xl font-black uppercase tracking-tight">Official DPI Scanner</h3>
                   <p className="text-[11px] text-gray-500 font-black tracking-widest uppercase">Registry Verification Terminal</p>
                 </div>
               </div>
               <button onClick={closeOfficialScanner} className="w-14 h-14 rounded-full bg-white/5 flex items-center justify-center hover:bg-white/10 transition-colors border border-white/10">
                 <X className="w-7 h-7" />
               </button>
            </div>

            <div className="flex-1 overflow-y-auto p-12 space-y-12">
               <div className="relative aspect-square bg-gray-950 rounded-[56px] overflow-hidden border-[12px] border-white shadow-2xl flex items-center justify-center group">
                 {!scanResult ? (
                   <>
                    <video ref={scannerVideoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-40 transition-opacity" />
                    <div className="absolute inset-0 border-[80px] border-black/50 pointer-events-none flex items-center justify-center">
                       <div className="w-full h-full border-4 border-white/10 rounded-[48px] border-dashed"></div>
                    </div>
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-80 h-80 border-4 border-green-500/30 rounded-[48px] animate-pulse"></div>
                    <div className="absolute inset-x-0 h-1.5 bg-green-500/50 shadow-[0_0_30px_rgba(34,197,94,1)] animate-scan-official pointer-events-none"></div>

                    {isVerifyingScan && (
                      <div className="absolute inset-0 bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white space-y-6 animate-in fade-in duration-500">
                        <Loader2 className="w-16 h-16 animate-spin text-green-500" />
                        <div className="text-center space-y-2">
                           <p className="text-sm font-black uppercase tracking-[0.3em] animate-pulse">DPI Cloud Matching...</p>
                           <p className="text-[10px] text-white/50 font-bold uppercase tracking-widest">Token Auth 921-X</p>
                        </div>
                      </div>
                    )}
                   </>
                 ) : scanResult === 'success' ? (
                   <div className="w-full h-full bg-green-50 flex flex-col items-center justify-center p-16 text-center space-y-10 animate-in zoom-in-95 duration-700">
                      <div className="w-32 h-32 bg-green-600 rounded-[48px] flex items-center justify-center shadow-2xl shadow-green-100 text-white animate-bounce border-[6px] border-white">
                        <Verified className="w-16 h-16" />
                      </div>
                      <div className="space-y-3">
                        <h4 className="text-4xl font-black text-green-950 tracking-tighter leading-none uppercase">Authentic Vendor</h4>
                        <div className="bg-green-100 text-green-800 px-6 py-2 rounded-full text-sm font-black tracking-widest uppercase inline-block border border-green-200">
                          Pre-Verification Success
                        </div>
                      </div>
                      <button onClick={() => setScanResult(null)} className="text-sm font-black text-green-800 uppercase tracking-[0.2em] border-b-4 border-green-200 pb-1.5 hover:text-green-950 transition-all active:scale-95">Clear for Registration</button>
                   </div>
                 ) : (
                   <div className="w-full h-full bg-red-50 flex flex-col items-center justify-center p-16 text-center space-y-8">
                      <div className="w-32 h-32 bg-red-600 rounded-[48px] flex items-center justify-center text-white shadow-2xl shadow-red-100">
                        <ShieldAlert className="w-16 h-16" />
                      </div>
                      <div className="space-y-2">
                        <h4 className="text-4xl font-black text-red-950 tracking-tighter leading-none">AUTH FAILED</h4>
                        <p className="text-sm font-bold text-red-700 uppercase tracking-widest">Registry Mismatch</p>
                      </div>
                      <button onClick={() => setScanResult(null)} className="px-12 py-5 bg-red-600 text-white rounded-[32px] font-black text-lg uppercase tracking-widest shadow-xl shadow-red-200 active:scale-95">Retry Scan</button>
                   </div>
                 )}
               </div>

               <div className="text-center space-y-8">
                 {!scanResult && (
                    <div className="space-y-6">
                      <p className="text-base font-medium text-gray-600 leading-relaxed max-w-sm mx-auto hindi">
                        सत्यापन के लिए विक्रेता के QR कोड को कैमरे के घेरे में लाएं। यह उत्तर प्रदेश शासन का प्रमाणित प्रशासनिक गेटवे है।
                      </p>
                      <button 
                        onClick={simulateOfficialScan}
                        disabled={isVerifyingScan}
                        className="w-full py-8 bg-gray-950 text-white rounded-[40px] font-black text-2xl flex items-center justify-center space-x-6 hover:bg-black transition-all shadow-2xl active:scale-95 disabled:opacity-50 group/scan"
                      >
                        {isVerifyingScan ? <Loader2 className="w-8 h-8 animate-spin" /> : <> <Camera className="w-8 h-8 group-hover/scan:scale-110 transition-transform" /> <span>SCAN MERCHANT IDENTITY</span> </>}
                      </button>
                    </div>
                 )}
                 <div className="flex items-center justify-center space-x-3 text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] opacity-50">
                    <Fingerprint className="w-4 h-4" />
                    <span>State Authentication Gateway • V4.2</span>
                 </div>
               </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes scan {
          0% { top: 15%; opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { top: 85%; opacity: 0; }
        }
        @keyframes scan-official {
          0% { top: 0%; opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { top: 100%; opacity: 0; }
        }
        .animate-scan {
          position: absolute;
          animation: scan 4s ease-in-out infinite;
        }
        .animate-scan-official {
          animation: scan-official 3s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default Registration;

export type Language = 'hi' | 'en';

export enum RegistrationStep {
  AUTH = 'AUTH',
  PROFILE = 'PROFILE',
  VERIFY_IDENTITY = 'VERIFY_IDENTITY',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED'
}

export interface ActivityLog {
  date: string;
  action: string;
}

export interface VendorProfile {
  id?: string;
  name: string;
  mobile: string;
  aadharNumber: string;
  businessType: string;
  location: {
    lat: number;
    lng: number;
    address: string;
  };
  vendingType: 'fixed' | 'mobile' | 'seasonal';
  isVerified: boolean;
  selfie?: string;
  aadharScan?: string;
  activeSchemes?: string[];
  loanStatus?: 'eligible' | 'applied' | 'under_review' | 'approved' | 'none';
  activityHistory?: ActivityLog[];
}

export interface Scheme {
  id: string;
  title: string;
  titleHi: string;
  description: string;
  descriptionHi: string;
  icon: string;
}

import React, { useState, createContext, useContext } from 'react';
import Layout from './components/Layout';
import Home from './pages/Home';
import Registration from './pages/Registration';
import Dashboard from './pages/Dashboard';
import { VendorProfile, Language } from './types';

interface LanguageContextType {
  lang: Language;
  setLang: (lang: Language) => void;
  t: (hi: string, en: string) => string;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) throw new Error('useLanguage must be used within a LanguageProvider');
  return context;
};

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'registration' | 'dashboard'>('home');
  const [profile, setProfile] = useState<VendorProfile | null>(null);
  const [lang, setLang] = useState<Language>('hi');

  const handleStartRegistration = () => setView('registration');

  const handleRegistrationComplete = (data: VendorProfile) => {
    setProfile(data);
    setView('dashboard');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const t = (hi: string, en: string) => (lang === 'hi' ? hi : en);

  return (
    <LanguageContext.Provider value={{ lang, setLang, t }}>
      <Layout>
        {view === 'home' && <Home onStart={handleStartRegistration} />}
        {view === 'registration' && <Registration onComplete={handleRegistrationComplete} />}
        {view === 'dashboard' && profile && <Dashboard profile={profile} />}
      </Layout>
    </LanguageContext.Provider>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff, RefreshCcw, Circle, Phone, ClipboardList, ScanLine, Settings2, Scan, X, ShieldAlert, Verified } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';
import { useLanguage } from '../App';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const { lang, t } = useLanguage();
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [isListeningAddress, setIsListeningAddress] = useState(false);
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' },
    activeSchemes: [],
    loanStatus: 'none',
    activityHistory: []
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [activeStream, setActiveStream] = useState<MediaStream | null>(null);

  // Official Scanner States
  const [isOfficialScannerOpen, setIsOfficialScannerOpen] = useState(false);
  const [isVerifyingScan, setIsVerifyingScan] = useState(false);
  const [scanResult, setScanResult] = useState<'success' | 'error' | null>(null);
  const scannerVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step, lang);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step, lang]);

  useEffect(() => {
    if (isCameraActive && activeStream && videoRef.current) {
      videoRef.current.srcObject = activeStream;
    }
  }, [isCameraActive, activeStream]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError(t('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।', 'Please enter a valid 10-digit mobile number.'));
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      setActiveStream(stream);
      setIsCameraActive(true);
    } catch (err) {
      setError(t('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।', 'Camera access failed. Please allow.'));
      console.error("Camera error:", err);
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      if (video.videoWidth === 0 || video.videoHeight === 0) {
        setError(t('कैमरा तैयार हो रहा है, कृपया पुनः प्रयास करें।', 'Camera is preparing, please try again.'));
        return;
      }

      const context = canvas.getContext('2d');
      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.translate(canvas.width, 0);
        context.scale(-1, 1);
        context.drawImage(video, 0, 0);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setSelfie(dataUrl);

        if (activeStream) {
          activeStream.getTracks().forEach(track => track.stop());
          setActiveStream(null);
        }
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") + t("लखनऊ मुख्य बाजार (स्वचालित)", "Lucknow Main Market (Auto-detected)")
            }
          }));
        },
        () => setError(t('स्थान प्राप्त करने में विफल।', 'Location access failed.')),
        { timeout: 10000 }
      );
    }
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);
    setTimeout(() => {
      if (result.success) {
        const finalProfile = { 
          ...profile, 
          mobile, 
          selfie, 
          aadharScan, 
          isVerified: true,
          activeSchemes: ['PM SVANidhi'],
          loanStatus: 'eligible' as const,
          activityHistory: [{ date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }), action: 'Registration Completed' }]
        };
        onComplete(finalProfile as VendorProfile);
      } else {
        setError(result.message || t('सत्यापन विफल।', 'Verification failed.'));
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 3000);
  };

  // Official Scanner Methods
  const openOfficialScanner = async () => {
    setIsOfficialScannerOpen(true);
    setScanResult(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (scannerVideoRef.current) {
        scannerVideoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied:", err);
      setError(t("कैमरा एक्सेस करने में असमर्थ।", "Unable to access camera."));
      setIsOfficialScannerOpen(false);
    }
  };

  const closeOfficialScanner = () => {
    if (scannerVideoRef.current && scannerVideoRef.current.srcObject) {
      const stream = scannerVideoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
    }
    setIsOfficialScannerOpen(false);
    setIsVerifyingScan(false);
    setScanResult(null);
  };

  const simulateOfficialScan = () => {
    setIsVerifyingScan(true);
    setTimeout(() => {
      setIsVerifyingScan(false);
      setScanResult('success');
    }, 2000);
  };

  const steps = [
    { id: RegistrationStep.AUTH, label: t('मोबाइल नंबर', 'Mobile'), sub: 'Mobile', icon: <Phone className="w-4 h-4" /> },
    { id: RegistrationStep.PROFILE, label: t('दुकान का विवरण', 'Business'), sub: 'Business', icon: <ClipboardList className="w-4 h-4" /> },
    { id: RegistrationStep.VERIFY_IDENTITY, label: t('सत्यापन', 'Identity'), sub: 'Identity', icon: <ScanLine className="w-4 h-4" /> },
    { id: RegistrationStep.PROCESSING, label: t('अंतिम प्रक्रिया', 'Finalizing'), sub: 'Finalizing', icon: <Settings2 className="w-4 h-4" /> },
  ];

  const currentStepIndex = steps.findIndex(s => s.id === step);
  const progressPercentage = ((currentStepIndex + 1) / steps.length) * 100;

  return (
    <div className="max-w-xl mx-auto px-4 py-16 md:py-24 animate-in fade-in duration-700">
      <div className="mb-14 space-y-8">
        <div className="flex justify-between items-end px-3">
          <div className="space-y-2">
            <h4 className="text-2xl font-black text-gray-900 tracking-tight">{t('पंजीकरण प्रगति', 'Registration Progress')}</h4>
            <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest flex items-center">
              <span className="flex h-2 w-2 rounded-full bg-orange-600 mr-2 animate-pulse"></span>
              {t(`कदम ${currentStepIndex + 1} / ${steps.length}`, `Step ${currentStepIndex + 1} of ${steps.length}`)}
            </p>
          </div>
          <div className="text-right">
