    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' },
    activeSchemes: [],
    loanStatus: 'none',
    activityHistory: []
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [activeStream, setActiveStream] = useState<MediaStream | null>(null);

  // Official Scanner States
  const [isOfficialScannerOpen, setIsOfficialScannerOpen] = useState(false);
  const [isVerifyingScan, setIsVerifyingScan] = useState(false);
  const [scanResult, setScanResult] = useState<'success' | 'error' | null>(null);
  const scannerVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step, lang);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step, lang]);

  useEffect(() => {
    if (isCameraActive && activeStream && videoRef.current) {
      videoRef.current.srcObject = activeStream;
    }
  }, [isCameraActive, activeStream]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError(t('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।', 'Please enter a valid 10-digit mobile number.'));
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      setActiveStream(stream);
      setIsCameraActive(true);
    } catch (err) {
      setError(t('कैमरा एक्सेस करने में विफल। कृपया अनुमति दें।', 'Camera access failed. Please allow.'));
      console.error("Camera error:", err);
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      if (video.videoWidth === 0 || video.videoHeight === 0) {
        setError(t('कैमरा तैयार हो रहा है, कृपया पुनः प्रयास करें।', 'Camera is preparing, please try again.'));
        return;
      }

      const context = canvas.getContext('2d');
      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.translate(canvas.width, 0);
        context.scale(-1, 1);
        context.drawImage(video, 0, 0);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setSelfie(dataUrl);

        if (activeStream) {
          activeStream.getTracks().forEach(track => track.stop());
          setActiveStream(null);
        }
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              ...prev.location!,
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: (prev.location?.address || "") || t("लखनऊ मुख्य बाजार (स्वचालित स्थान)", "Lucknow Main Market (Auto-detected)")
            }
          }));
        },
        () => setError(t('स्थान प्राप्त करने में विफल। कृपया मैन्युअल रूप से दर्ज करें।', 'Location access failed. Please enter manually.')),
        { timeout: 10000 }
      );
    }
  };

  const runDPIVerification = async () => {
    setStep(RegistrationStep.PROCESSING);
    const result = await verifyVendorIdentity(profile);

    // Simulate complex matching logic
    setTimeout(() => {
      if (result.success) {
        const finalProfile = { 
          ...profile, 
          mobile, 
          selfie, 
          aadharScan, 
          isVerified: true,
          id: `UPV-${Math.random().toString(36).substr(2, 9).toUpperCase()}`, // Unique Registry ID for QR
          activeSchemes: ['PM SVANidhi'],
          loanStatus: 'eligible' as const,
          activityHistory: [{ date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }), action: 'Registration Completed' }]
        };
        onComplete(finalProfile as VendorProfile);
      } else {
        setError(result.message || t('सत्यापन विफल। आधार और सेल्फी का मिलान नहीं हुआ।', 'Verification failed. Aadhar and Selfie mismatch.'));
        setStep(RegistrationStep.VERIFY_IDENTITY);
      }
    }, 4500); // Slightly longer for "processing" feel
  };

  // Official Scanner Methods
  const openOfficialScanner = async () => {
    setIsOfficialScannerOpen(true);
    setScanResult(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (scannerVideoRef.current) {
        scannerVideoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied:", err);
      setError(t("कैमरा एक्सेस करने में असमर्थ।", "Unable to access camera."));
      setIsOfficialScannerOpen(false);
    }
  };

  const closeOfficialScanner = () => {
    if (scannerVideoRef.current && scannerVideoRef.current.srcObject) {
      const stream = scannerVideoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
    }
    setIsOfficialScannerOpen(false);
    setIsVerifyingScan(false);
    setScanResult(null);
  };

  const simulateOfficialScan = () => {
    setIsVerifyingScan(true);
    setTimeout(() => {
      setIsVerifyingScan(false);
      setScanResult('success');
    }, 2000);
  };

  const steps = [
    { id: RegistrationStep.AUTH, label: t('मोबाइल नंबर', 'Mobile'), sub: 'Mobile', icon: <Phone className="w-4 h-4" /> },
    { id: RegistrationStep.PROFILE, label: t('दुकान का विवरण', 'Business'), sub: 'Business', icon: <ClipboardList className="w-4 h-4" /> },
    { id: RegistrationStep.VERIFY_IDENTITY, label: t('सत्यापन', 'Identity'), sub: 'Identity', icon: <ScanLine className="w-4 h-4" /> },
    { id: RegistrationStep.PROCESSING, label: t('अंतिम प्रक्रिया', 'Finalizing'), sub: 'Finalizing', icon: <Settings2 className="w-4 h-4" /> },
  ];

  const currentStepIndex = steps.findIndex(s => s.id === step);
  const progressPercentage = ((currentStepIndex + 1) / steps.length) * 100;

  return (
    <div className="max-w-xl mx-auto px-4 py-16 md:py-24 animate-in fade-in duration-700">
      <div className="mb-14 space-y-8">
        <div className="flex justify-between items-end px-3">
          <div className="space-y-2">
            <h4 className="text-2xl font-black text-gray-900 tracking-tight">{t('पंजीकरण प्रगति', 'Registration Progress')}</h4>
            <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest flex items-center">
              <span className="flex h-2 w-2 rounded-full bg-orange-600 mr-2 animate-pulse"></span>
              {t(`कदम ${currentStepIndex + 1} / ${steps.length}`, `Step ${currentStepIndex + 1} of ${steps.length}`)}
            </p>
          </div>
          <div className="text-right">
            <p className="text-4xl font-black text-gray-900 leading-none">{Math.round(progressPercentage)}%</p>
          </div>
        </div>

        <div className="relative pt-6 pb-2">
          <div className="absolute top-1/2 -translate-y-1/2 left-0 w-full h-2 bg-gray-100 rounded-full"></div>
          <div 
            className="absolute top-1/2 -translate-y-1/2 left-0 h-2 bg-orange-600 rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(249,115,22,0.4)]"
            style={{ width: `${progressPercentage}%` }}
          ></div>
        </div>
      </div>

      <div className="mb-12 flex items-center space-x-6 bg-orange-50 p-8 rounded-[40px] border border-orange-100 shadow-sm">
        <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center shadow-md relative shrink-0">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping"></div>
          <Mic className="w-7 h-7 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-[10px] text-orange-800 uppercase font-black tracking-widest mb-1.5 opacity-60">{t('AI सहायक (AI Guidance)', 'AI Assistant')}</p>
          <p className="text-lg font-bold text-orange-900 leading-relaxed italic">
            "{voiceHint || t('लोड हो रहा है...', 'Loading...')}"
          </p>
        </div>
      </div>

      {error && (
        <div className="mb-8 p-6 bg-red-50 border border-red-100 rounded-[32px] flex items-center space-x-5 text-red-700">
          <AlertCircle className="w-6 h-6 shrink-0" />
          <p className="text-sm font-black">{error}</p>
        </div>
      )}

      <div className="bg-white p-10 md:p-16 rounded-[56px] shadow-2xl border border-gray-100 min-h-[500px] flex flex-col animate-in zoom-in-95 duration-500 relative">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-12">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('स्वागत है', 'Welcome')}</h2>
            <div className="space-y-8">
              <div className="space-y-3">
                <label className="text-[11px] font-black text-gray-400 uppercase tracking-widest ml-1">{t('मोबाइल नंबर', 'Mobile Number')}</label>
                <div className="relative group">
                  <span className="absolute left-8 top-1/2 -translate-y-1/2 text-gray-400 font-black text-2xl">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000 00000"
                    maxLength={10}
                    className="w-full pl-22 pr-8 py-7 bg-gray-50 border-3 border-transparent rounded-[28px] focus:bg-white focus:border-orange-500 focus:ring-8 focus:ring-orange-500/10 transition-all text-3xl tracking-[0.25em] font-black"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-7 bg-orange-600 text-white rounded-[28px] font-black text-2xl flex items-center justify-center space-x-4 shadow-2xl shadow-orange-600/30 hover:bg-orange-700 hover:scale-[1.03] transition-all disabled:opacity-50">
                {isVerifying ? <Loader2 className="w-8 h-8 animate-spin" /> : <><span>{t('OTP प्राप्त करें', 'Get OTP')}</span> <ArrowRight className="w-7 h-7" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-8">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('व्यापारी विवरण', 'Vendor Details')}</h2>
            <div className="space-y-5">
              <input 
                type="text"
                placeholder={t("पूर्ण नाम (Full Name)", "Full Name")}
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg shadow-sm"
                value={profile.name}
                onChange={(e) => setProfile({...profile, name: e.target.value})}
              />
              <input 
                type="tel"
                placeholder={t("आधार नंबर (Aadhar Number)", "Aadhar Number")}
                maxLength={12}
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg tracking-[0.2em] shadow-sm"
                value={profile.aadharNumber}
                onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
              />
              <div className="relative">
                <select 
                  className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg appearance-none shadow-sm"
                  value={profile.businessType}
                  onChange={(e) => setProfile({...profile, businessType: e.target.value})}
                >
                  <option value="">{t('व्यवसाय श्रेणी (Business Category)', 'Business Category')}</option>
                  {BUSINESS_TYPES.map(t_type => <option key={t_type.id} value={t_type.label}>{t_type.label}</option>)}
                </select>
                <div className="absolute right-6 top-1/2 -translate-y-1/2 pointer-events-none">
                   <ChevronDown className="w-5 h-5 text-gray-400" />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center px-1">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t('व्यवसाय का स्थान (Business Location)', 'Business Location')}</label>
                   <button 
                    onClick={handleLocationDetect}
                    className="flex items-center space-x-2 text-[10px] font-black text-orange-600 uppercase tracking-widest bg-orange-50 px-3 py-1.5 rounded-full border border-orange-100 hover:bg-orange-100 transition-all"
                   >
                     <Crosshair className="w-3.5 h-3.5" />
                     <span>{t('जीपीएस से खोजें', 'Detect via GPS')}</span>
                   </button>
                </div>
                <textarea 
                  className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] h-32 resize-none font-bold text-base focus:bg-white focus:border-orange-500 transition-all shadow-sm"
                  placeholder={t("व्यवसाय का पूरा पता दर्ज करें (Address)", "Enter complete business address")}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
                {profile.location?.lat !== 0 && (
                   <div className="flex items-center space-x-2 bg-green-50 p-3 rounded-2xl border border-green-100 animate-in fade-in">
                      <MapPin className="w-4 h-4 text-green-600" />
                      <span className="text-[10px] font-black text-green-700 uppercase tracking-widest">{t('सटीक स्थान पिन किया गया', 'Precise Location Pinned')}</span>
                   </div>
                )}
              </div>
            </div>
            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || !profile.businessType || !profile.location?.address) {
                  setError(t('कृपया सभी जानकारी भरें।', 'Please fill all details.'));
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-6 bg-orange-600 text-white rounded-[28px] font-black text-xl mt-4 flex items-center justify-center space-x-4 shadow-xl hover:bg-orange-700 transition-all active:scale-95"
            >
              <span>{t('अगला कदम: सत्यापन', 'Next: Verification')}</span>
              <ArrowRight className="w-7 h-7" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-12">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('डिजिटल सत्यापन', 'Digital Verify')}</h2>
            <div className="space-y-10">
              <div className="space-y-5">
                <p className="text-[11px] font-black text-gray-400 uppercase tracking-widest text-center">{t('१. अपनी सेल्फी लें (Live Photo)', '1. Take a Live Selfie')}</p>
                <div className="relative aspect-[4/3] bg-gray-950 rounded-[48px] overflow-hidden shadow-2xl border-4 border-white">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-5 hover:bg-gray-900 transition-colors">
                      <Camera className="w-14 h-14" />
                      <span className="font-black text-xs uppercase tracking-[0.3em]">{t('कैमरा चालू करें', 'Enable Camera')}</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <button onClick={() => {setSelfie(null); startCamera();}} className="absolute bottom-6 right-6 bg-white/20 backdrop-blur-md p-4 rounded-full border border-white/20 text-white hover:bg-white/40 transition-all">
                        <RefreshCcw className="w-6 h-6" />
                      </button>
                    </div>
                  ) : (
                    <>
                      <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
                      <div className="absolute inset-0 border-[30px] border-black/40 pointer-events-none flex items-center justify-center">
                         <div className="w-48 h-64 border-2 border-white/30 rounded-full border-dashed animate-pulse"></div>
                      </div>
                      <button onClick={captureSelfie} className="absolute bottom-10 left-1/2 -translate-x-1/2 w-24 h-24 bg-white/20 backdrop-blur-3xl rounded-full border-4 border-white/50 flex items-center justify-center shadow-2xl active:scale-90 transition-all">
                        <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center">
                          <Camera className="w-8 h-8 text-orange-600" />
                        </div>
                      </button>
                    </>
                  )}
                </div>
              </div>

              <div className="space-y-5">
                <p className="text-[11px] font-black text-gray-400 uppercase tracking-widest text-center">{t('२. आधार कार्ड अपलोड करें', '2. Upload Aadhar Card')}</p>
                <label className={`relative h-48 border-4 border-dashed rounded-[48px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50/50' : 'border-gray-100 bg-gray-50/50 hover:bg-white hover:border-orange-300'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-2">
                       <CheckCircle2 className="w-12 h-12 text-green-500" />
                       <span className="font-black text-green-700 uppercase text-[10px] tracking-widest">{t('अपलोड सफल', 'Upload Success')}</span>
                    </div>
                  ) : (
                    <>
                      <Upload className="w-10 h-10 mb-4 text-gray-300" />
                      <span className="font-black text-gray-400 uppercase text-[10px] tracking-widest">{t('फाइल चुनें', 'Choose File')}</span>
                    </>
                  )}
                </label>
              </div>

              <button 
                onClick={runDPIVerification}
                disabled={!selfie || !aadharScan}
                className="w-full py-7 bg-orange-600 text-white rounded-[28px] font-black text-2xl flex items-center justify-center space-x-4 disabled:opacity-30 shadow-2xl shadow-orange-600/20"
              >
                <span>{t('सत्यापित करें और QR प्राप्त करें', 'Verify & Generate QR')}</span>
                <Fingerprint className="w-7 h-7" />
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-12 animate-in fade-in duration-700">
            <div className="relative">
              <div className="w-48 h-48 border-8 border-orange-50 rounded-[56px] animate-pulse"></div>
              <div className="absolute inset-0 w-48 h-48 border-8 border-orange-600 border-t-transparent rounded-[56px] animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center overflow-hidden rounded-[48px]">
                {selfie && <img src={selfie} className="w-full h-full object-cover opacity-50 grayscale" />}
                <div className="absolute inset-0 flex items-center justify-center">
                  <ScanLine className="w-20 h-20 text-orange-600 animate-bounce" />
                </div>
                <div className="absolute inset-x-0 h-1 bg-orange-500 shadow-[0_0_20px_rgba(249,115,22,1)] animate-facial-scan"></div>
              </div>
            </div>
            <div className="space-y-4">
              <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('सत्यापन और QR निर्माण...', 'Verification & QR Creation...')}</h2>
              <div className="flex flex-col items-center space-y-2">
                 <p className="text-gray-500 font-medium text-lg italic">"{t('आधार और सेल्फी का मिलान किया जा रहा है', 'Matching Aadhar with Selfie biometric')}"</p>
                 <div className="flex items-center space-x-3 text-[10px] font-black text-orange-600 uppercase tracking-widest">
                    <Loader2 className="w-4 h-4 animate-spin" />
                    <span>DPI GATEWAY CONNECTED</span>
                 </div>
              </div>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-12 inline-flex items-center text-gray-400 font-black text-[11px] uppercase tracking-[0.4em] hover:text-orange-600 transition-all"
          >
            <ArrowLeft className="w-5 h-5 mr-3" />
            {t('पीछे (Back)', 'Go Back')}
          </button>
        )}
      </div>

      <style>{`
        @keyframes facial-scan {
          0% { top: 0%; opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { top: 100%; opacity: 0; }
        }
        .animate-facial-scan {
          position: absolute;
          animation: facial-scan 2.5s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

// Add Missing ChevronDown Icon
const ChevronDown = ({ className }: { className?: string }) => (
  <svg className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" />
  </svg>
);

export default Registration;

import { GoogleGenAI, Type } from "@google/genai";
import { Language } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getVoiceGuidance = async (step: string, lang: Language = 'hi') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide a short, respectful, and helpful instruction in ${lang === 'hi' ? 'Hindi' : 'English'} for a vendor currently at the "${step}" step of registration on the Uttar Pradesh Vendor Portal. 
      Steps are: AUTH (Mobile), PROFILE (Details), VERIFY_IDENTITY (Selfie/Aadhar), PROCESSING (DPI Verification). 
      Keep it under 20 words. Focus on dignity and ease.`,
      config: {
        systemInstruction: `You are a helpful and respectful administrative assistant for the Government of Uttar Pradesh. If lang is 'hi', use formal but warm Hindi (Aap format). If 'en', use professional yet encouraging English.`,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Voice Guidance Error:", error);
    if (lang === 'en') {
        if (step.includes('AUTH')) return "Please enter your mobile number to begin.";
        if (step.includes('PROFILE')) return "Please enter your name, Aadhar and business details.";
        if (step.includes('VERIFY')) return "Take a selfie and upload your Aadhar to verify identity.";
        return "Please enter your details to continue.";
    }
    if (step.includes('AUTH')) return "कृपया आगे बढ़ने के लिए अपना मोबाइल नंबर दर्ज करें।";
    if (step.includes('PROFILE')) return "कृपया अपना नाम, आधार नंबर और व्यापार की जानकारी भरें।";
    if (step.includes('VERIFY')) return "अपनी पहचान सत्यापित करने के लिए एक सेल्फी लें और आधार कार्ड अपलोड करें।";
    return "प्रक्रिया जारी रखने के लिए कृपया अपनी जानकारी दर्ज करें।";
  }
};

export const verifyVendorIdentity = async (vendorData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Simulate a high-security DPI (Digital Public Infrastructure) verification for the State of Uttar Pradesh. 
      Vendor Name: ${vendorData.name}
      Aadhar: ${vendorData.aadharNumber}
      Business Location captured: ${vendorData.location?.lat}, ${vendorData.location?.lng}
      Tasks:
      1. Verify Aadhar details against national registry.
      2. Perform AI Facial Matching between the live selfie and the Aadhar card photo.
      3. Validate the business location.
      Respond with a JSON status indicating verification success and a short encouraging message specifically mentioning the facial match success.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            success: { type: Type.BOOLEAN },
            message: { type: Type.STRING },
            confidenceScore: { type: Type.NUMBER },
            facialMatchResult: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text || '{"success": true, "message": "सत्यापन सफल रहा। आधार और चेहरे का मिलान हो गया है।", "confidenceScore": 0.99, "facialMatchResult": "98% Biometric Match"}');
  } catch (error) {
    console.error("DPI Verification Simulation Error:", error);
    return { success: true, message: "डेटाबेस मिलान और बायोमेट्रिक सत्यापन सफल रहा।", confidenceScore: 1.0, facialMatchResult: "Verified" };
  }
};

