import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff, RefreshCcw, Circle, Phone, ClipboardList, ScanLine, Settings2, Scan, X, ShieldAlert, Verified, Crosshair, Info } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';
import { useLanguage } from '../App';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const { lang, t } = useLanguage();
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' },
    activeSchemes: [],
    loanStatus: 'none',
    activityHistory: []
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [activeStream, setActiveStream] = useState<MediaStream | null>(null);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step, lang);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step, lang]);

  useEffect(() => {
    if (isCameraActive && activeStream && videoRef.current) {
      videoRef.current.srcObject = activeStream;
    }
    return () => {
      if (activeStream) {
        activeStream.getTracks().forEach(track => track.stop());
      }
    };
  }, [isCameraActive, activeStream]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError(t('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।', 'Please enter a valid 10-digit mobile number.'));
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      setActiveStream(stream);
      setIsCameraActive(true);
    } catch (err) {
      setError(t('कैमरा एक्सेस करने में विफल। कृपया सेटिंग्स में अनुमति दें।', 'Camera access failed. Please allow in settings.'));
      console.error("Camera error:", err);
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      const context = canvas.getContext('2d');
      if (context) {
        canvas.width = video.videoWidth || 640;
        canvas.height = video.videoHeight || 480;
        context.translate(canvas.width, 0);
        context.scale(-1, 1);
        context.drawImage(video, 0, 0);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setSelfie(dataUrl);

        if (activeStream) {
          activeStream.getTracks().forEach(track => track.stop());
          setActiveStream(null);
        }
        setIsCameraActive(false);
      }
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              ...prev.location!,
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: prev.location?.address || t("लखनऊ मुख्य बाजार", "Lucknow Main Market")
            }
          }));
        },
        () => setError(t('स्थान प्राप्त करने में विफल।', 'Location access failed.')),
        { timeout: 5000 }
      );
    }
  };

  const runDPIVerification = async () => {
    setError(null);
    setStep(RegistrationStep.PROCESSING);

    try {
      const result = await verifyVendorIdentity({ ...profile, selfie, aadharScan });

      // Minimum processing time for dignity/authenticity feel
      setTimeout(() => {
        if (result && result.success) {
          const finalProfile = { 
            ...profile, 
            mobile, 
            selfie, 
            aadharScan, 
            isVerified: true,
            id: `UPV-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
            activeSchemes: ['PM SVANidhi'],
            loanStatus: 'eligible' as const,
            activityHistory: [{ 
              date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }), 
              action: 'Registration Completed via DPI Portal' 
            }]
          };
          onComplete(finalProfile as VendorProfile);
        } else {
          setError(result?.message || t('सत्यापन विफल। कृपया पुनः प्रयास करें।', 'Verification failed. Please try again.'));
          setStep(RegistrationStep.VERIFY_IDENTITY);
        }
      }, 3500);
    } catch (err) {
      console.error("Verification error:", err);
      setError(t('सिस्टम त्रुटि। कृपया बाद में प्रयास करें।', 'System error. Please try again later.'));
      setStep(RegistrationStep.VERIFY_IDENTITY);
    }
  };

  const steps = [
    { id: RegistrationStep.AUTH, label: t('मोबाइल', 'Mobile') },
    { id: RegistrationStep.PROFILE, label: t('विवरण', 'Profile') },
    { id: RegistrationStep.VERIFY_IDENTITY, label: t('सत्यापन', 'Verify') },
    { id: RegistrationStep.PROCESSING, label: t('प्रगति', 'Status') },
  ];

  const currentStepIndex = steps.findIndex(s => s.id === step);
  const progressPercentage = ((currentStepIndex + 1) / steps.length) * 100;

  return (
    <div className="max-w-xl mx-auto px-4 py-16 md:py-24 animate-in fade-in duration-700">
      {/* PROGRESS TRACKER */}
      <div className="mb-14 space-y-8">
        <div className="flex justify-between items-end px-3">
          <div className="space-y-2">
            <h4 className="text-2xl font-black text-gray-900 tracking-tight">{t('पंजीकरण प्रगति', 'Registration Progress')}</h4>
            <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest flex items-center">
              <span className="flex h-2 w-2 rounded-full bg-orange-600 mr-2 animate-pulse"></span>
              {t(`चरण ${currentStepIndex + 1} / ${steps.length}`, `Step ${currentStepIndex + 1} of ${steps.length}`)}
            </p>
          </div>
          <div className="text-right">
            <p className="text-4xl font-black text-gray-900 leading-none">{Math.round(progressPercentage)}%</p>
          </div>
        </div>

        <div className="relative h-2 bg-gray-100 rounded-full overflow-hidden shadow-inner">
          <div 
            className="absolute top-0 left-0 h-full bg-orange-600 rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(249,115,22,0.4)]"
            style={{ width: `${progressPercentage}%` }}
          ></div>
        </div>
      </div>

      {/* AI ASSISTANT PILL */}
      <div className="mb-12 flex items-center space-x-6 bg-orange-50 p-8 rounded-[40px] border border-orange-100 shadow-sm">
        <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center shadow-md relative shrink-0">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping"></div>
          <Mic className="w-7 h-7 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-[10px] text-orange-800 uppercase font-black tracking-widest mb-1.5 opacity-60">{t('सरकारी सहायक', 'Administrative Assistant')}</p>
          <p className="text-lg font-bold text-orange-900 leading-relaxed italic">
            "{voiceHint || t('लोड हो रहा है...', 'Loading...')}"
          </p>
        </div>
      </div>

      {/* ERROR MESSAGE */}
      {error && (
        <div className="mb-8 p-6 bg-red-50 border border-red-100 rounded-[32px] flex items-center space-x-5 text-red-700 animate-in slide-in-from-top-4">
          <AlertCircle className="w-6 h-6 shrink-0" />
          <p className="text-sm font-black">{error}</p>
        </div>
      )}

      {/* MAIN CONTAINER */}
      <div className="bg-white p-10 md:p-16 rounded-[56px] shadow-2xl border border-gray-100 min-h-[550px] flex flex-col animate-in zoom-in-95 duration-500 relative overflow-hidden">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-12">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('मोबाइल प्रमाणीकरण', 'Mobile Authentication')}</h2>
            <div className="space-y-8">
              <div className="space-y-3">
                <label className="text-[11px] font-black text-gray-400 uppercase tracking-widest ml-1">{t('मोबाइल नंबर', 'Mobile Number')}</label>
                <div className="relative group">
                  <span className="absolute left-8 top-1/2 -translate-y-1/2 text-gray-400 font-black text-2xl">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000 00000"
                    maxLength={10}
                    className="w-full pl-22 pr-8 py-7 bg-gray-50 border-3 border-transparent rounded-[28px] focus:bg-white focus:border-orange-500 focus:ring-8 focus:ring-orange-500/10 transition-all text-3xl tracking-[0.25em] font-black"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-7 bg-orange-600 text-white rounded-[28px] font-black text-2xl flex items-center justify-center space-x-4 shadow-2xl shadow-orange-600/30 hover:bg-orange-700 hover:scale-[1.03] transition-all disabled:opacity-50 active:scale-95">
                {isVerifying ? <Loader2 className="w-8 h-8 animate-spin" /> : <><span>{t('OTP प्राप्त करें', 'Get OTP')}</span> <ArrowRight className="w-7 h-7" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-8">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('व्यवसाय विवरण', 'Business Profile')}</h2>
            <div className="space-y-5">
              <input 
                type="text"
                placeholder={t("पूर्ण नाम (Full Name)", "Full Name")}
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg shadow-sm"
                value={profile.name}
                onChange={(e) => setProfile({...profile, name: e.target.value})}
              />
              <input 
                type="tel"
                placeholder={t("आधार नंबर (12-Digit Aadhar)", "12-Digit Aadhar Number")}
                maxLength={12}
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg tracking-[0.2em] shadow-sm"
                value={profile.aadharNumber}
                onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
              />
              <select 
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg shadow-sm appearance-none"
                value={profile.businessType}
                onChange={(e) => setProfile({...profile, businessType: e.target.value})}
              >
                <option value="">{t('व्यवसाय की श्रेणी', 'Select Business Category')}</option>
                {BUSINESS_TYPES.map(t_type => <option key={t_type.id} value={t_type.label}>{t_type.label}</option>)}
              </select>
              <div className="space-y-4">
                <div className="flex justify-between items-center px-1">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t('दुकान का पता', 'Shop Address')}</label>
                   <button 
                    onClick={handleLocationDetect}
                    className="flex items-center space-x-2 text-[10px] font-black text-orange-600 uppercase tracking-widest bg-orange-50 px-3 py-1.5 rounded-full border border-orange-100 hover:bg-orange-100 transition-all"
                   >
                     <MapPin className="w-3.5 h-3.5" />
                     <span>{t('स्थान पिन करें', 'Pin via GPS')}</span>
                   </button>
                </div>
                <textarea 
                  className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] h-24 resize-none font-bold text-base focus:bg-white focus:border-orange-500 transition-all shadow-sm"
                  placeholder={t("अपना पूरा पता यहाँ लिखें", "Enter complete address")}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>
            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || profile.aadharNumber.length < 12 || !profile.businessType) {
                  setError(t('कृपया आधार और सभी अनिवार्य विवरण भरें।', 'Please fill Aadhar and all mandatory fields.'));
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-6 bg-orange-600 text-white rounded-[28px] font-black text-xl mt-4 flex items-center justify-center space-x-4 shadow-xl hover:bg-orange-700 transition-all active:scale-95"
            >
              <span>{t('सत्यापन के लिए आगे बढ़ें', 'Proceed to Verify')}</span>
              <ArrowRight className="w-7 h-7" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-12">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('डिजिटल पहचान', 'Digital Identity')}</h2>
            <div className="space-y-10">
              <div className="space-y-5">
                <p className="text-[11px] font-black text-gray-400 uppercase tracking-widest text-center">{t('१. लाइव सेल्फी लें', '1. Capture Live Selfie')}</p>
                <div className="relative aspect-square md:aspect-video bg-gray-950 rounded-[48px] overflow-hidden shadow-2xl border-4 border-white">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-5 hover:bg-gray-900 transition-colors">
                      <Camera className="w-14 h-14" />
                      <span className="font-black text-xs uppercase tracking-[0.3em]">{t('कैमरा शुरू करें', 'Enable Camera')}</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <button onClick={() => {setSelfie(null); startCamera();}} className="absolute bottom-6 right-6 bg-orange-600 p-4 rounded-full text-white shadow-xl hover:bg-orange-700 transition-all">
                        <RefreshCcw className="w-6 h-6" />
                      </button>
                    </div>
                  ) : (
                    <>
                      <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
                      <div className="absolute inset-0 border-[30px] border-black/30 pointer-events-none flex items-center justify-center">
                         <div className="w-64 h-64 border-2 border-white/30 rounded-full border-dashed animate-pulse"></div>
                      </div>
                      <button onClick={captureSelfie} className="absolute bottom-10 left-1/2 -translate-x-1/2 w-20 h-20 bg-white/20 backdrop-blur-3xl rounded-full border-4 border-white flex items-center justify-center shadow-2xl active:scale-90 transition-all">
                        <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center">
                          <Camera className="w-7 h-7 text-orange-600" />
                        </div>
                      </button>
                    </>
                  )}
                </div>
              </div>

              <div className="space-y-5">
                <p className="text-[11px] font-black text-gray-400 uppercase tracking-widest text-center">{t('२. आधार कार्ड फोटो', '2. Aadhar Card Photo')}</p>
                <label className={`relative h-40 border-4 border-dashed rounded-[48px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-100 bg-gray-50 hover:bg-white hover:border-orange-300'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-2">
                       <CheckCircle2 className="w-10 h-10 text-green-500" />
                       <span className="font-black text-green-700 uppercase text-[10px] tracking-widest">{t('फोटो अपलोड हो गई', 'Photo Uploaded')}</span>
                    </div>
                  ) : (
                    <>
                      <Upload className="w-10 h-10 mb-2 text-gray-300" />
                      <span className="font-black text-gray-400 uppercase text-[10px] tracking-widest">{t('फाइल चुनें', 'Choose File')}</span>
                    </>
                  )}
                </label>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={runDPIVerification}
                  disabled={!selfie || !aadharScan}
                  className={`w-full py-8 bg-orange-600 text-white rounded-[32px] font-black text-2xl flex items-center justify-center space-x-5 shadow-2xl transition-all ${(!selfie || !aadharScan) ? 'opacity-30 cursor-not-allowed grayscale' : 'hover:bg-orange-700 hover:scale-[1.02] active:scale-[0.98]'}`}
                >
                  <span>{t('सत्यापित करें और QR प्राप्त करें', 'Verify & Get QR')}</span>
                  <Fingerprint className="w-8 h-8" />
                </button>
                {(!selfie || !aadharScan) && (
                  <div className="flex items-center justify-center space-x-2 text-gray-400 text-[10px] font-bold uppercase tracking-widest">
                    <Info className="w-3.5 h-3.5" />
                    <span>{t('सत्यापन के लिए सेल्फी और आधार अनिवार्य है', 'Selfie & Aadhar required to verify')}</span>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-12 animate-in fade-in duration-700">
            <div className="relative">
              <div className="w-48 h-48 border-8 border-orange-50 rounded-[64px] animate-pulse shadow-inner"></div>
              <div className="absolute inset-0 w-48 h-48 border-8 border-orange-600 border-t-transparent rounded-[64px] animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center overflow-hidden rounded-[56px]">
                {selfie && <img src={selfie} className="w-full h-full object-cover opacity-40 grayscale" alt="Biometric Processing" />}
                <div className="absolute inset-0 bg-orange-500/10 backdrop-blur-[2px]"></div>
                <div className="absolute inset-x-0 h-1.5 bg-orange-500 shadow-[0_0_30px_rgba(249,115,22,1)] animate-facial-scan"></div>
                <ScanLine className="w-16 h-16 text-orange-600 relative z-10 opacity-60" />
              </div>
            </div>
            <div className="space-y-4">
              <h2 className="text-4xl font-black text-gray-900 tracking-tight leading-none">{t('पहचान की जाँच...', 'Verifying Identity...')}</h2>
              <div className="space-y-3">
                 <p className="text-gray-500 font-medium text-lg italic leading-relaxed">"{t('आधार और बायोमेट्रिक्स का मिलान हो रहा है', 'Matching Aadhar with Biometric data')}"</p>
                 <div className="flex items-center justify-center space-x-3 text-[10px] font-black text-orange-600 uppercase tracking-[0.3em]">
                    <div className="w-2 h-2 bg-orange-600 rounded-full animate-pulse"></div>
                    <span>DPI REGISTRY CONNECTED</span>
                 </div>
              </div>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-12 inline-flex items-center text-gray-400 font-black text-[11px] uppercase tracking-[0.4em] hover:text-orange-600 transition-all group"
          >
            <ArrowLeft className="w-5 h-5 mr-3 group-hover:-translate-x-1 transition-transform" />
            {t('वापस (Back)', 'Go Back')}
          </button>
        )}
      </div>

      <style>{`
        @keyframes facial-scan {
          0% { top: 0%; opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { top: 100%; opacity: 0; }
        }
        .animate-facial-scan {
          position: absolute;
          animation: facial-scan 2.5s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default Registration;

import { GoogleGenAI, Type } from "@google/genai";
import { Language } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getVoiceGuidance = async (step: string, lang: Language = 'hi') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide a short, respectful, and helpful instruction in ${lang === 'hi' ? 'Hindi' : 'English'} for a vendor currently at the "${step}" step of registration on the Uttar Pradesh Vendor Portal. 
      Steps are: AUTH (Mobile), PROFILE (Details), VERIFY_IDENTITY (Selfie/Aadhar), PROCESSING (DPI Verification). 
      Keep it under 20 words. Focus on dignity and ease.`,
      config: {
        systemInstruction: `You are a helpful and respectful administrative assistant for the Government of Uttar Pradesh. If lang is 'hi', use formal but warm Hindi (Aap format). If 'en', use professional yet encouraging English.`,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Voice Guidance Error:", error);
    if (lang === 'en') {
        if (step.includes('AUTH')) return "Please enter your mobile number to begin your registration.";
        if (step.includes('PROFILE')) return "Please provide your name, Aadhar number and shop details.";
        if (step.includes('VERIFY')) return "Take a clear selfie and upload your Aadhar photo for verification.";
        return "Please complete the information to proceed.";
    }
    if (step.includes('AUTH')) return "कृपया अपना पंजीकरण शुरू करने के लिए मोबाइल नंबर दर्ज करें।";
    if (step.includes('PROFILE')) return "कृपया अपना नाम, आधार संख्या और दुकान का विवरण प्रदान करें।";
    if (step.includes('VERIFY')) return "सत्यापन के लिए एक साफ सेल्फी लें और अपना आधार फोटो अपलोड करें।";
    return "आगे बढ़ने के लिए कृपया जानकारी पूरी करें।";
  }
};

export const verifyVendorIdentity = async (vendorData: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Simulate a high-security DPI (Digital Public Infrastructure) verification for the State of Uttar Pradesh. 
      Vendor Name: ${vendorData.name}
      Aadhar: ${vendorData.aadharNumber}
      Selfie/Aadhar Data present: ${!!vendorData.selfie} / ${!!vendorData.aadharScan}

      Tasks:
      1. Cross-reference identity with State Merchant Registry.
      2. Perform AI Biometric Comparison between Live Selfie and Document.
      3. Validate Aadhaar validity.

      Respond with a JSON status indicating success and an encouraging message mentioning successful biometric match.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            success: { type: Type.BOOLEAN },
            message: { type: Type.STRING },
            confidenceScore: { type: Type.NUMBER },
            facialMatchResult: { type: Type.STRING }
          },
          required: ["success", "message"]
        }
      }
    });
    const parsed = JSON.parse(response.text || '{"success": true, "message": "सत्यापन सफल रहा। आधार और चेहरे का मिलान हो गया है।"}');
    return parsed;
  } catch (error) {
    console.error("DPI Verification Simulation Error:", error);
    // Robust fallback if API fails
    return { 
      success: true, 
      message: "डेटाबेस मिलान और बायोमेट्रिक सत्यापन सफल रहा।", 
      confidenceScore: 0.98, 
      facialMatchResult: "Verified" 
    };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { RegistrationStep, VendorProfile } from '../types';
import { BUSINESS_TYPES } from '../constants';
import { ArrowRight, ArrowLeft, Mic, MapPin, Camera, Loader2, CheckCircle2, ShieldCheck, AlertCircle, User, Fingerprint, Upload, MicOff, RefreshCcw, Circle, Phone, ClipboardList, ScanLine, Settings2, Scan, X, ShieldAlert, Verified, Crosshair, Info } from 'lucide-react';
import { getVoiceGuidance, verifyVendorIdentity } from '../services/geminiService';
import { useLanguage } from '../App';

interface RegistrationProps {
  onComplete: (profile: VendorProfile) => void;
}

const Registration: React.FC<RegistrationProps> = ({ onComplete }) => {
  const { lang, t } = useLanguage();
  const [step, setStep] = useState<RegistrationStep>(RegistrationStep.AUTH);
  const [mobile, setMobile] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const [voiceHint, setVoiceHint] = useState('');
  const [profile, setProfile] = useState<Partial<VendorProfile>>({
    name: '',
    mobile: '',
    aadharNumber: '',
    businessType: '',
    vendingType: 'fixed',
    location: { lat: 0, lng: 0, address: '' },
    activeSchemes: [],
    loanStatus: 'none',
    activityHistory: []
  });

  const [selfie, setSelfie] = useState<string | null>(null);
  const [aadharScan, setAadharScan] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [activeStream, setActiveStream] = useState<MediaStream | null>(null);

  useEffect(() => {
    const fetchHint = async () => {
      setError(null);
      const hint = await getVoiceGuidance(step, lang);
      setVoiceHint(hint || '');
    };
    fetchHint();
  }, [step, lang]);

  useEffect(() => {
    if (isCameraActive && activeStream && videoRef.current) {
      videoRef.current.srcObject = activeStream;
    }
    return () => {
      if (activeStream) {
        activeStream.getTracks().forEach(track => track.stop());
      }
    };
  }, [isCameraActive, activeStream]);

  const prevStep = () => {
    if (step === RegistrationStep.PROFILE) {
      setStep(RegistrationStep.AUTH);
    } else if (step === RegistrationStep.VERIFY_IDENTITY) {
      setStep(RegistrationStep.PROFILE);
    }
  };

  const handleAuth = () => {
    setError(null);
    if (mobile.length !== 10) {
      setError(t('कृपया 10 अंकों का मान्य मोबाइल नंबर दर्ज करें।', 'Please enter a valid 10-digit mobile number.'));
      return;
    }
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      setStep(RegistrationStep.PROFILE);
    }, 1200);
  };

  const startCamera = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      setActiveStream(stream);
      setIsCameraActive(true);
    } catch (err) {
      setError(t('कैमरा एक्सेस करने में विफल। कृपया सेटिंग्स में अनुमति दें।', 'Camera access failed. Please allow in settings.'));
      console.error("Camera error:", err);
    }
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      const context = canvas.getContext('2d');
      if (context) {
        // Use real video dimensions or fallback to 640x480
        const width = video.videoWidth || 640;
        const height = video.videoHeight || 480;

        canvas.width = width;
        canvas.height = height;

        // Horizontal flip for mirroring
        context.translate(canvas.width, 0);
        context.scale(-1, 1);
        context.drawImage(video, 0, 0, width, height);

        try {
          const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
          setSelfie(dataUrl);

          if (activeStream) {
            activeStream.getTracks().forEach(track => track.stop());
            setActiveStream(null);
          }
          setIsCameraActive(false);
          setError(null);
        } catch (e) {
          setError(t('फोटो लेने में त्रुटि हुई।', 'Error capturing photo.'));
          console.error(e);
        }
      } else {
        setError(t('कैनवास लोड नहीं हो सका।', 'Canvas could not be initialized.'));
      }
    } else {
      setError(t('कैमरा अभी तैयार नहीं है।', 'Camera is not ready.'));
    }
  };

  const handleAadharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAadharScan(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLocationDetect = () => {
    setError(null);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setProfile(prev => ({
            ...prev,
            location: {
              ...prev.location!,
              lat: position.coords.latitude,
              lng: position.coords.longitude,
              address: prev.location?.address || t("लखनऊ मुख्य बाजार", "Lucknow Main Market")
            }
          }));
        },
        () => setError(t('स्थान प्राप्त करने में विफल।', 'Location access failed.')),
        { timeout: 5000 }
      );
    }
  };

  const runDPIVerification = async () => {
    if (!selfie || !aadharScan) return;

    setError(null);
    setStep(RegistrationStep.PROCESSING);

    try {
      const result = await verifyVendorIdentity({ ...profile, selfie, aadharScan });

      // Delay to simulate rigorous system checks
      setTimeout(() => {
        if (result && result.success) {
          const finalProfile: VendorProfile = { 
            name: profile.name || '',
            mobile: mobile,
            aadharNumber: profile.aadharNumber || '',
            businessType: profile.businessType || '',
            location: profile.location || { lat: 0, lng: 0, address: '' },
            vendingType: profile.vendingType || 'fixed',
            selfie: selfie,
            aadharScan: aadharScan,
            isVerified: true,
            id: `UPV-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
            activeSchemes: ['PM SVANidhi'],
            loanStatus: 'eligible' as const,
            activityHistory: [{ 
              date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }), 
              action: 'Registration Completed via DPI Portal' 
            }]
          };
          onComplete(finalProfile);
        } else {
          setError(result?.message || t('सत्यापन विफल। कृपया पुनः प्रयास करें।', 'Verification failed. Please try again.'));
          setStep(RegistrationStep.VERIFY_IDENTITY);
        }
      }, 3500);
    } catch (err) {
      console.error("Verification error:", err);
      setError(t('सिस्टम त्रुटि। कृपया बाद में प्रयास करें।', 'System error. Please try again later.'));
      setStep(RegistrationStep.VERIFY_IDENTITY);
    }
  };

  const steps = [
    { id: RegistrationStep.AUTH, label: t('मोबाइल', 'Mobile') },
    { id: RegistrationStep.PROFILE, label: t('विवरण', 'Profile') },
    { id: RegistrationStep.VERIFY_IDENTITY, label: t('सत्यापन', 'Verify') },
    { id: RegistrationStep.PROCESSING, label: t('प्रगति', 'Status') },
  ];

  const currentStepIndex = steps.findIndex(s => s.id === step);
  const progressPercentage = ((currentStepIndex + 1) / steps.length) * 100;

  // Check if verification button should be enabled
  const canVerify = selfie !== null && aadharScan !== null;

  return (
    <div className="max-w-xl mx-auto px-4 py-16 md:py-24 animate-in fade-in duration-700">
      {/* Hidden canvas for capture */}
      <canvas ref={canvasRef} className="hidden" aria-hidden="true" />

      {/* PROGRESS TRACKER */}
      <div className="mb-14 space-y-8">
        <div className="flex justify-between items-end px-3">
          <div className="space-y-2">
            <h4 className="text-2xl font-black text-gray-900 tracking-tight">{t('पंजीकरण प्रगति', 'Registration Progress')}</h4>
            <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest flex items-center">
              <span className="flex h-2 w-2 rounded-full bg-orange-600 mr-2 animate-pulse"></span>
              {t(`चरण ${currentStepIndex + 1} / ${steps.length}`, `Step ${currentStepIndex + 1} of ${steps.length}`)}
            </p>
          </div>
          <div className="text-right">
            <p className="text-4xl font-black text-gray-900 leading-none">{Math.round(progressPercentage)}%</p>
          </div>
        </div>

        <div className="relative h-2 bg-gray-100 rounded-full overflow-hidden shadow-inner">
          <div 
            className="absolute top-0 left-0 h-full bg-orange-600 rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(249,115,22,0.4)]"
            style={{ width: `${progressPercentage}%` }}
          ></div>
        </div>
      </div>

      {/* AI ASSISTANT PILL */}
      <div className="mb-12 flex items-center space-x-6 bg-orange-50 p-8 rounded-[40px] border border-orange-100 shadow-sm">
        <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center shadow-md relative shrink-0">
          <div className="absolute inset-0 bg-orange-600/10 rounded-full animate-ping"></div>
          <Mic className="w-7 h-7 text-orange-600 relative z-10" />
        </div>
        <div className="flex-1">
          <p className="text-[10px] text-orange-800 uppercase font-black tracking-widest mb-1.5 opacity-60">{t('सरकारी सहायक', 'Administrative Assistant')}</p>
          <p className="text-lg font-bold text-orange-900 leading-relaxed italic">
            "{voiceHint || t('लोड हो रहा है...', 'Loading...')}"
          </p>
        </div>
      </div>

      {/* ERROR MESSAGE */}
      {error && (
        <div className="mb-8 p-6 bg-red-50 border border-red-100 rounded-[32px] flex items-center space-x-5 text-red-700 animate-in slide-in-from-top-4">
          <AlertCircle className="w-6 h-6 shrink-0" />
          <p className="text-sm font-black">{error}</p>
        </div>
      )}

      {/* MAIN CONTAINER */}
      <div className="bg-white p-10 md:p-16 rounded-[56px] shadow-2xl border border-gray-100 min-h-[550px] flex flex-col animate-in zoom-in-95 duration-500 relative overflow-hidden">

        {step === RegistrationStep.AUTH && (
          <div className="flex-1 space-y-12">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('मोबाइल प्रमाणीकरण', 'Mobile Authentication')}</h2>
            <div className="space-y-8">
              <div className="space-y-3">
                <label className="text-[11px] font-black text-gray-400 uppercase tracking-widest ml-1">{t('मोबाइल नंबर', 'Mobile Number')}</label>
                <div className="relative group">
                  <span className="absolute left-8 top-1/2 -translate-y-1/2 text-gray-400 font-black text-2xl">+91</span>
                  <input 
                    type="tel"
                    placeholder="00000 00000"
                    maxLength={10}
                    className="w-full pl-22 pr-8 py-7 bg-gray-50 border-3 border-transparent rounded-[28px] focus:bg-white focus:border-orange-500 focus:ring-8 focus:ring-orange-500/10 transition-all text-3xl tracking-[0.25em] font-black"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value.replace(/\D/g, ''))}
                  />
                </div>
              </div>
              <button onClick={handleAuth} disabled={isVerifying} className="w-full py-7 bg-orange-600 text-white rounded-[28px] font-black text-2xl flex items-center justify-center space-x-4 shadow-2xl shadow-orange-600/30 hover:bg-orange-700 hover:scale-[1.03] transition-all disabled:opacity-50 active:scale-95">
                {isVerifying ? <Loader2 className="w-8 h-8 animate-spin" /> : <><span>{t('OTP प्राप्त करें', 'Get OTP')}</span> <ArrowRight className="w-7 h-7" /></>}
              </button>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROFILE && (
          <div className="flex-1 space-y-8">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('व्यवसाय विवरण', 'Business Profile')}</h2>
            <div className="space-y-5">
              <input 
                type="text"
                placeholder={t("पूर्ण नाम (Full Name)", "Full Name")}
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg shadow-sm"
                value={profile.name}
                onChange={(e) => setProfile({...profile, name: e.target.value})}
              />
              <input 
                type="tel"
                placeholder={t("आधार नंबर (12-Digit Aadhar)", "12-Digit Aadhar Number")}
                maxLength={12}
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg tracking-[0.2em] shadow-sm"
                value={profile.aadharNumber}
                onChange={(e) => setProfile({...profile, aadharNumber: e.target.value.replace(/\D/g, '')})}
              />
              <select 
                className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] focus:bg-white focus:border-orange-500 transition-all font-black text-lg shadow-sm appearance-none"
                value={profile.businessType}
                onChange={(e) => setProfile({...profile, businessType: e.target.value})}
              >
                <option value="">{t('व्यवसाय की श्रेणी', 'Select Business Category')}</option>
                {BUSINESS_TYPES.map(t_type => <option key={t_type.id} value={t_type.label}>{t_type.label}</option>)}
              </select>
              <div className="space-y-4">
                <div className="flex justify-between items-center px-1">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t('दुकान का पता', 'Shop Address')}</label>
                   <button 
                    onClick={handleLocationDetect}
                    className="flex items-center space-x-2 text-[10px] font-black text-orange-600 uppercase tracking-widest bg-orange-50 px-3 py-1.5 rounded-full border border-orange-100 hover:bg-orange-100 transition-all"
                   >
                     <MapPin className="w-3.5 h-3.5" />
                     <span>{t('स्थान पिन करें', 'Pin via GPS')}</span>
                   </button>
                </div>
                <textarea 
                  className="w-full p-5 bg-gray-50 border-3 border-transparent rounded-[24px] h-24 resize-none font-bold text-base focus:bg-white focus:border-orange-500 transition-all shadow-sm"
                  placeholder={t("अपना पूरा पता यहाँ लिखें", "Enter complete address")}
                  value={profile.location?.address}
                  onChange={(e) => setProfile({...profile, location: {...profile.location!, address: e.target.value}})}
                />
              </div>
            </div>
            <button 
              onClick={() => {
                if(!profile.name || !profile.aadharNumber || profile.aadharNumber.length < 12 || !profile.businessType) {
                  setError(t('कृपया आधार और सभी अनिवार्य विवरण भरें।', 'Please fill Aadhar and all mandatory fields.'));
                } else {
                  setStep(RegistrationStep.VERIFY_IDENTITY);
                }
              }}
              className="w-full py-6 bg-orange-600 text-white rounded-[28px] font-black text-xl mt-4 flex items-center justify-center space-x-4 shadow-xl hover:bg-orange-700 transition-all active:scale-95"
            >
              <span>{t('सत्यापन के लिए आगे बढ़ें', 'Proceed to Verify')}</span>
              <ArrowRight className="w-7 h-7" />
            </button>
          </div>
        )}

        {step === RegistrationStep.VERIFY_IDENTITY && (
          <div className="flex-1 space-y-12">
            <h2 className="text-4xl font-black text-gray-900 tracking-tight">{t('डिजिटल पहचान', 'Digital Identity')}</h2>
            <div className="space-y-10">
              <div className="space-y-5">
                <p className="text-[11px] font-black text-gray-400 uppercase tracking-widest text-center">{t('१. लाइव सेल्फी लें', '1. Capture Live Selfie')}</p>
                <div className="relative aspect-square md:aspect-video bg-gray-950 rounded-[48px] overflow-hidden shadow-2xl border-4 border-white">
                  {!isCameraActive && !selfie ? (
                    <button onClick={startCamera} className="absolute inset-0 flex flex-col items-center justify-center text-white/50 space-y-5 hover:bg-gray-900 transition-colors">
                      <Camera className="w-14 h-14" />
                      <span className="font-black text-xs uppercase tracking-[0.3em]">{t('कैमरा शुरू करें', 'Enable Camera')}</span>
                    </button>
                  ) : selfie ? (
                    <div className="relative w-full h-full group">
                      <img src={selfie} className="w-full h-full object-cover" alt="Selfie" />
                      <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                        <CheckCircle2 className="w-20 h-20 text-white" />
                      </div>
                      <button onClick={() => {setSelfie(null); startCamera();}} className="absolute bottom-6 right-6 bg-orange-600 p-4 rounded-full text-white shadow-xl hover:bg-orange-700 transition-all">
                        <RefreshCcw className="w-6 h-6" />
                      </button>
                    </div>
                  ) : (
                    <>
                      <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover scale-x-[-1]" />
                      <div className="absolute inset-0 border-[30px] border-black/30 pointer-events-none flex items-center justify-center">
                         <div className="w-64 h-64 border-2 border-white/30 rounded-full border-dashed animate-pulse"></div>
                      </div>
                      <button onClick={captureSelfie} className="absolute bottom-10 left-1/2 -translate-x-1/2 w-20 h-20 bg-white/20 backdrop-blur-3xl rounded-full border-4 border-white flex items-center justify-center shadow-2xl active:scale-90 transition-all">
                        <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center">
                          <Camera className="w-7 h-7 text-orange-600" />
                        </div>
                      </button>
                    </>
                  )}
                </div>
              </div>

              <div className="space-y-5">
                <p className="text-[11px] font-black text-gray-400 uppercase tracking-widest text-center">{t('२. आधार कार्ड फोटो', '2. Aadhar Card Photo')}</p>
                <label className={`relative h-40 border-4 border-dashed rounded-[48px] flex flex-col items-center justify-center cursor-pointer transition-all ${aadharScan ? 'border-green-200 bg-green-50' : 'border-gray-100 bg-gray-50 hover:bg-white hover:border-orange-300'}`}>
                  <input type="file" accept="image/*" className="hidden" onChange={handleAadharUpload} />
                  {aadharScan ? (
                    <div className="flex flex-col items-center space-y-2">
                       <CheckCircle2 className="w-10 h-10 text-green-500" />
                       <span className="font-black text-green-700 uppercase text-[10px] tracking-widest">{t('फोटो अपलोड हो गई', 'Photo Uploaded')}</span>
                    </div>
                  ) : (
                    <>
                      <Upload className="w-10 h-10 mb-2 text-gray-300" />
                      <span className="font-black text-gray-400 uppercase text-[10px] tracking-widest">{t('फाइल चुनें', 'Choose File')}</span>
                    </>
                  )}
                </label>
              </div>

              <div className="space-y-4">
                <button 
                  onClick={runDPIVerification}
                  disabled={!canVerify}
                  className={`w-full py-8 bg-orange-600 text-white rounded-[32px] font-black text-2xl flex items-center justify-center space-x-5 shadow-2xl transition-all ${!canVerify ? 'opacity-30 cursor-not-allowed grayscale' : 'hover:bg-orange-700 hover:scale-[1.02] active:scale-[0.98]'}`}
                >
                  <span>{t('सत्यापित करें और QR प्राप्त करें', 'Verify & Get QR')}</span>
                  <Fingerprint className="w-8 h-8" />
                </button>
                {!canVerify && (
                  <div className="flex items-center justify-center space-x-2 text-gray-400 text-[10px] font-bold uppercase tracking-widest">
                    <Info className="w-3.5 h-3.5" />
                    <span>{t('सत्यापन के लिए सेल्फी और आधार अनिवार्य है', 'Selfie & Aadhar required to verify')}</span>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {step === RegistrationStep.PROCESSING && (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-12 animate-in fade-in duration-700">
            <div className="relative">
              <div className="w-48 h-48 border-8 border-orange-50 rounded-[64px] animate-pulse shadow-inner"></div>
              <div className="absolute inset-0 w-48 h-48 border-8 border-orange-600 border-t-transparent rounded-[64px] animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center overflow-hidden rounded-[56px]">
                {selfie && <img src={selfie} className="w-full h-full object-cover opacity-40 grayscale" alt="Biometric Processing" />}
                <div className="absolute inset-0 bg-orange-500/10 backdrop-blur-[2px]"></div>
                <div className="absolute inset-x-0 h-1.5 bg-orange-500 shadow-[0_0_30px_rgba(249,115,22,1)] animate-facial-scan"></div>
                <ScanLine className="w-16 h-16 text-orange-600 relative z-10 opacity-60" />
              </div>
            </div>
            <div className="space-y-4">
              <h2 className="text-4xl font-black text-gray-900 tracking-tight leading-none">{t('पहचान की जाँच...', 'Verifying Identity...')}</h2>
              <div className="space-y-3">
                 <p className="text-gray-500 font-medium text-lg italic leading-relaxed">"{t('आधार और बायोमेट्रिक्स का मिलान हो रहा है', 'Matching Aadhar with Biometric data')}"</p>
                 <div className="flex items-center justify-center space-x-3 text-[10px] font-black text-orange-600 uppercase tracking-[0.3em]">
                    <div className="w-2 h-2 bg-orange-600 rounded-full animate-pulse"></div>
                    <span>DPI REGISTRY CONNECTED</span>
                 </div>
              </div>
            </div>
          </div>
        )}

        {step !== RegistrationStep.AUTH && step !== RegistrationStep.PROCESSING && (
          <button 
            onClick={prevStep}
            className="mt-12 inline-flex items-center text-gray-400 font-black text-[11px] uppercase tracking-[0.4em] hover:text-orange-600 transition-all group"
          >
            <ArrowLeft className="w-5 h-5 mr-3 group-hover:-translate-x-1 transition-transform" />
            {t('वापस (Back)', 'Go Back')}
          </button>
        )}
      </div>

      <style>{`
        @keyframes facial-scan {
          0% { top: 0%; opacity: 0; }
          20% { opacity: 1; }
          80% { opacity: 1; }
          100% { top: 100%; opacity: 0; }
        }
        .animate-facial-scan {
          position: absolute;
          animation: facial-scan 2.5s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default Registration;

